INSERT INTO `ENTREPRISE` (`entreprise_id`, `entreprise_nom`, `entreprise_taille`, `entreprise_siteweb`, `entreprise_email`, `entreprise_telephone`, `entreprise_rue`, `entreprise_extrait`, `entreprise_presentation`, `entreprise_nb_stagiaires`, `localite_id`, `secteur_id`, `entreprise_archive`) VALUES
(1, 'Divia (Keolis Dijon)', 450, 'https://www.divia.fr', 'contact@divia.fr', '0380767676', '12 Place Grangier', 'Réseau de transport en commun de l\'agglomération dijonnaise.', 'Divia est le réseau de transports en commun de Dijon Métropole, exploité par Keolis. Avec plus de 30 lignes de bus et le célèbre tram, Divia assure chaque jour la mobilité de milliers d\'habitants. L\'entreprise investit massivement dans des solutions écologiques (bus électriques, stations multimodales) et dans la digitalisation de ses services pour offrir une expérience voyageur moderne et fluide.', 4, 1, 14, 0),
(2, 'Urgo Group', 1200, 'https://www.urgo.com', 'rh@urgo.com', '0380442200', '42 Rue de Longvic', 'Groupe pharmaceutique et de soins, référence en pansements et dispositifs médicaux.', 'Urgo Group est un groupe familial français fondé à Dijon, spécialisé dans les soins de la peau, les dispositifs médicaux et les compléments alimentaires. Présent dans plus de 40 pays, le groupe s\'appuie sur des marques reconnues telles qu\'Urgo, Alvarez, Laboratoire Thissen et Bioptigen. L\'innovation est au cœur de sa stratégie avec un centre R&D actif basé à Chenôve.', 6, 1, 13, 0),
(3, 'Syclef', 380, 'https://www.syclef.fr', 'contact@syclef.fr', '0380562200', '7 Allée des Sorbiers', 'Leader français en installation et maintenance de systèmes frigorifiques et CVC.', 'Syclef est le leader français de la réfrigération commerciale et du génie climatique. Basée à Dijon, l\'entreprise intervient pour des clients grands comptes dans la distribution alimentaire, l\'industrie et le tertiaire. Son réseau d\'agences couvre tout le territoire national. Syclef s\'engage dans une politique de développement durable en favorisant les fluides frigorigènes à faible impact environnemental.', 5, 1, 15, 0),
(4, 'Maped', 600, 'https://www.maped.com', 'recrutement@maped.com', '0380735959', 'Zone Industrielle Cap Nord', 'Fabricant français iconique de fournitures scolaires et de bureau.', 'Maped est une entreprise française fondée en 1947 à Dijon, devenue l\'un des leaders mondiaux de la fourniture scolaire et de bureau. Ses produits (ciseaux, compas, cartables, colles) sont distribués dans plus de 120 pays. L\'entreprise concilie créativité, qualité et responsabilité environnementale en développant des gammes éco-conçues. Ses équipes de design et de marketing en font un acteur innovant reconnu à l\'international.', 8, 1, 10, 0),
(5, 'Crédit Agricole Centre-Est', 2100, 'https://www.ca-centrest.fr', 'contact@ca-centrest.fr', '0380417777', '1 Place de la Bourse', 'Banque régionale ancrée dans la Bourgogne-Franche-Comté au service des particuliers et pros.', 'La Caisse Régionale Crédit Agricole Centre-Est est l\'une des plus importantes caisses régionales du groupe Crédit Agricole. Implantée à Dijon, elle compte des centaines d\'agences en Bourgogne-Franche-Comté et Rhône-Alpes. La banque accompagne aussi bien les particuliers que les professionnels, agriculteurs et grandes entreprises, avec une offre complète de produits financiers, d\'épargne et d\'assurance.', 12, 1, 3, 0),
(6, 'Dalkia (EDF Group) - Dijon', 800, 'https://www.dalkia.fr', 'contact.dijon@dalkia.fr', '0380657800', '5 Rue du Transvaal', 'Filiale EDF spécialisée dans l\'efficacité énergétique et les services aux bâtiments.', 'Dalkia, filiale du groupe EDF, est un acteur majeur de l\'efficacité énergétique en France. L\'agence de Dijon gère des contrats de chauffage urbain, de maintenance d\'installations thermiques et de transition énergétique pour des collectivités, bailleurs sociaux et industriels de Bourgogne. Dalkia s\'inscrit dans la transition écologique en développant des solutions à base d\'énergies renouvelables et de récupération de chaleur.', 5, 1, 15, 0),
(7, 'Lundbeck France', 300, 'https://www.lundbeck.com/fr', 'contact@lundbeck.fr', '0383369000', '10 Rue du Bois de la Champelle', 'Laboratoire pharmaceutique spécialisé dans les maladies du cerveau.', 'Lundbeck France est la filiale française du groupe pharmaceutique danois H. Lundbeck A/S, spécialisé dans le traitement des maladies du cerveau (dépression, schizophrénie, maladie d\'Alzheimer). Le site nancéien intègre des activités de R&D, de production et de distribution. L\'entreprise est reconnue pour ses innovations thérapeutiques et son engagement éthique fort en matière de responsabilité sociale.', 5, 2, 13, 0),
(8, 'Altia (Groupe BGL)', 220, 'https://www.altia-ingenierie.fr', 'rh@altia-ingenierie.fr', '0383902020', '27 Rue Lionnois', 'Bureau d\'ingénierie pluridisciplinaire spécialisé en construction et énergie.', 'Altia est un bureau d\'études techniques et d\'ingénierie implanté à Nancy. L\'entreprise intervient dans les domaines du bâtiment, de l\'industrie et de l\'énergie avec des compétences en structure, fluides, électricité et thermique. Elle accompagne maîtres d\'ouvrage publics et privés sur des projets complexes, de la conception à la réception. Son équipe pluridisciplinaire garantit des solutions techniques performantes et durables.', 4, 2, 6, 0),
(9, 'Groupe Vitalia - Polyclinique Louis Pasteur', 500, 'https://www.vitalia.fr', 'contact@polycliniquelouispasteur.fr', '0383937000', '4 Rue Foller', 'Polyclinique privée de référence dans le Grand Est, offrant soins chirurgicaux et médicaux.', 'La Polyclinique Louis Pasteur, membre du groupe Vitalia, est un établissement de santé privé reconnu à Nancy. Elle propose une large gamme de soins chirurgicaux, médicaux et obstétriques avec des plateaux techniques de pointe. Résolument tournée vers la qualité des soins et le bien-être des patients, la polyclinique investit continuellement dans ses équipements et la formation de ses équipes médicales et paramédicales.', 6, 2, 13, 0),
(10, 'Sopra Steria - Nancy', 4500, 'https://www.soprasteria.com', 'nancy@soprasteria.com', '0383985000', '12 Place Stanislas', 'Leader européen de la transformation numérique, présent à Nancy.', 'Sopra Steria est l\'un des leaders européens de la transformation numérique. Son agence de Nancy accompagne des clients institutionnels et industriels dans leurs projets de digitalisation, d\'intégration de systèmes et de cybersécurité. L\'agence nancéienne est reconnue pour son expertise dans le secteur public et industriel. Sopra Steria est un employeur engagé, labellisé « Top Employer » et signataire du Pacte mondial de l\'ONU.', 10, 2, 11, 0),
(11, 'Brasserie de Saint-Avold (Heineken France)', 180, 'https://www.heinekenfrance.fr', 'contact.stav@heinekenfrance.fr', '0387928000', 'Zone Industrielle de Saint-Avold', 'Site de production Heineken France dans le Grand Est, brassant des millions d\'hectolitres.', 'La Brasserie de Saint-Avold est l\'un des sites de production du groupe Heineken en France. Bien que basée à Saint-Avold, elle recrute régulièrement des stagiaires via le campus CESI de Nancy. L\'usine brase plusieurs bières emblématiques et s\'inscrit dans une démarche qualité et environnementale ambitieuse avec des objectifs de réduction de consommation d\'eau et d\'empreinte carbone. Les équipes techniques, logistiques et qualité accueillent des profils variés.', 5, 2, 1, 0),
(12, 'Altrad', 900, 'https://www.altrad.com', 'rh@altrad.com', '0387628500', '15 Rue de l\'Industrie', 'Groupe industriel mondial spécialisé dans les services et équipements industriels.', 'Altrad est un groupe industriel international dont les racines régionales sont ancrées dans l\'Est de la France. Spécialisé dans les services industriels (maintenance, échafaudage, nettoyage industriel) et la fabrication d\'équipements (malaxeurs, bétonnières, échafaudages), le groupe est présent dans plus de 50 pays. Ses équipes locales à Nancy gèrent des contrats avec de grands donneurs d\'ordre industriels et accompagnent leur montée en compétences.', 7, 2, 10, 0),
(13, 'Vranken-Pommery Monopole', 600, 'https://www.vrankenpommery.fr', 'contact@vrankenpommery.fr', '0326614556', '5 Place du Général Gouraud', 'Maison de Champagne réputée, parmi les plus grandes du monde.', 'Vranken-Pommery Monopole est l\'un des plus grands groupes de Champagne au monde avec des maisons telles que Pommery, Heidsieck & Co Monopole et Charles Lafitte. Le siège rémois est au cœur d\'un vignoble exceptionnel. L\'entreprise allie tradition viticole centenaire et innovation marketing pour exporter ses cuvées dans plus de 100 pays. Elle recrute régulièrement sur des profils commerce international, marketing et logistique.', 8, 3, 1, 0),
(14, 'Européenne de Produits Réfractaires (EPR - Saint-Gobain)', 420, 'https://www.saintgobainceramics.com', 'recrutement.epr@saint-gobain.com', '0326824000', 'Rue des Grandes Loges', 'Site industriel Saint-Gobain spécialisé dans les matériaux réfractaires haute performance.', 'EPR est une filiale du groupe Saint-Gobain spécialisée dans la production de matériaux réfractaires destinés à l\'industrie du verre, de la sidérurgie et de la cimenterie. L\'usine de Reims est l\'une des plus modernes d\'Europe dans ce domaine. Elle combine procédés chimiques et minéralogiques avancés pour produire des briques et poudres réfractaires de haute qualité. Les ingénieurs et techniciens y trouvent des projets industriels stimulants.', 6, 3, 10, 0),
(15, 'Bouygues Telecom Entreprises - Reims', 3500, 'https://www.bouyguestelecom-entreprises.fr', 'contact.reims@bouyguestelecom.fr', '0326777777', '12 Rue Buirette', 'Opérateur télécom B2B de référence, accompagnant les entreprises dans leur connectivité.', 'Bouygues Telecom Entreprises est la branche dédiée aux professionnels et entreprises de Bouygues Telecom. L\'agence de Reims accompagne les entreprises champenoises dans leurs projets de transformation numérique : déploiement fibre, solutions cloud, cybersécurité, téléphonie d\'entreprise. Les équipes techniques et commerciales de l\'agence sont reconnues pour leur réactivité et leur expertise locale.', 7, 3, 11, 0),
(16, 'G+D Currency Technology France', 280, 'https://www.gi-de.com', 'contact@gd-currency.fr', '0326472000', 'rue de la Neuvillette', 'Spécialiste mondial des solutions de sécurité pour la monnaie fiduciaire et les paiements.', 'G+D Currency Technology est une filiale du groupe allemand Giesecke+Devrient, leader mondial dans les solutions de sécurité pour billets de banque et paiements. L\'usine de Reims est un site stratégique qui produit des substrats de billets et des solutions d\'authentification pour des banques centrales du monde entier. L\'environnement de travail est exigeant et valorisant pour les profils techniques, qualité et ingénierie.', 4, 3, 10, 0),
(17, 'BRED Banque Populaire - Champagne', 350, 'https://www.bred.fr', 'contact.champagne@bred.fr', '0326473000', '2 Rue Condorcet', 'Banque coopérative régionale forte d\'un ancrage local en Champagne-Ardenne.', 'La BRED Banque Populaire est une banque coopérative présente dans de nombreuses régions françaises. Son pôle Champagne, basé à Reims, accompagne les particuliers, professionnels et PME locales avec une gamme complète de solutions bancaires et d\'assurance. Reconnue pour la qualité de ses conseils et son ancrage territorial, la BRED affiche un modèle mutualiste centré sur la satisfaction client et la fidélité de ses collaborateurs.', 5, 3, 3, 0),
(18, 'Strasbourg Congrès & Evénements', 90, 'https://www.strasbourg-events.com', 'contact@strasbourg-events.com', '0388376767', '1 Place du Palais des Congrès', 'Organisateur professionnel d\'événements et congrès internationaux à Strasbourg.', 'Strasbourg Congrès & Evénements est la régie officielle du Palais de la Musique et des Congrès de Strasbourg. Ville siège du Parlement européen, Strasbourg accueille chaque année des centaines d\'événements internationaux. La structure gère la logistique, la communication et la coordination de ces événements avec des équipes multilingues et polyvalentes. Un environnement stimulant pour des profils en communication, événementiel et gestion de projet.', 3, 4, 5, 0),
(19, 'Butagaz', 900, 'https://www.butagaz.fr', 'recrutement@butagaz.fr', '0388556600', '35 Rue de la Fonderie', 'Leader français de la distribution de gaz liquéfié auprès des particuliers et professionnels.', 'Butagaz est l\'un des leaders français de la distribution de gaz liquéfié (propane, butane) et du multi-énergie (électricité, fioul). Avec son siège social à Strasbourg, Butagaz dessert des millions de foyers et d\'entreprises sur tout le territoire. La société investit dans la transition énergétique avec des solutions biogaz et hydrogène vert. Ses équipes en marketing, digital, logistique et commercial offrent de nombreuses opportunités de stage.', 10, 4, 15, 0),
(20, 'Syngenta France', 600, 'https://www.syngenta.fr', 'syngenta.france@syngenta.com', '0388414141', '12 Chemin de l\'Houssière', 'Leader mondial des semences et de la protection des cultures, ancré en Alsace.', 'Syngenta est un leader mondial de l\'agrochimie et des semences. Sa filiale française, implantée à Strasbourg, assure la distribution et le support technique pour les agriculteurs français. L\'entreprise développe des solutions innovantes pour améliorer la productivité agricole tout en réduisant l\'impact environnemental. Les équipes alsaciennes couvrent des domaines variés : R&D, marketing, formation agricole et réglementation.', 6, 4, 1, 0),
(21, 'Capgemini - Strasbourg', 5000, 'https://www.capgemini.com', 'strasbourg@capgemini.com', '0388214000', '9 Place de la République', 'Groupe international leader en conseil, services technologiques et transformation digitale.', 'Capgemini est l\'un des leaders mondiaux du conseil en transformation numérique, des services informatiques et de l\'ingénierie. L\'agence de Strasbourg intervient notamment pour des clients dans les secteurs bancaire, industriel et public de la région Grand Est. Elle propose des projets ambitieux en développement logiciel, cloud, cybersécurité et data. Capgemini est un employeur reconnu pour sa diversité et ses parcours de carrière évolutifs.', 12, 4, 11, 0),
(22, 'La Poste - Direction Grand Est', 3500, 'https://www.laposte.fr', 'contact.grandest@laposte.fr', '0388779900', '10 Avenue de la Forêt-Noire', 'Opérateur postal historique en mutation vers les services numériques et la logistique.', 'La Poste est un groupe public français en pleine transformation vers le numérique. Sa Direction Grand Est, basée à Strasbourg, gère les opérations postales, bancaires (La Banque Postale) et logistiques (Colissimo) de la région. La Poste développe des nouveaux services liés à la mobilité, l\'inclusion numérique et la silver économie. Les stages proposés couvrent des domaines variés : RH, marketing, logistique, digital et gestion.', 9, 4, 14, 0),
(23, 'ArcelorMittal France - Florange', 5000, 'https://www.arcelormittal.com/france', 'contact.france@arcelormittal.com', '0382593000', 'Rue des Tilleuls, Florange', 'Premier producteur mondial d\'acier, avec un site majeur en Lorraine.', 'ArcelorMittal est le numéro un mondial de la production d\'acier. Le site lorrain, proche de Thionville, est l\'un des plus importants du groupe en France. Il produit des aciers à haute résistance pour l\'automobile et la construction. L\'entreprise investit massivement dans la décarbonation de la production sidérurgique avec son projet XCarb. Les ingénieurs, techniciens et profils de gestion y trouvent des projets industriels d\'envergure.', 10, 5, 10, 0),
(24, 'Florange Assurances (MAIF Moselle)', 200, 'https://www.maif.fr', 'contact.moselle@maif.fr', '0387569000', '5 Avenue de la République', 'Mutuelle d\'assurance militante, reconnue pour son engagement sociétal et sa qualité de service.', 'La MAIF est une mutuelle d\'assurance fondée en 1934, reconnue pour ses valeurs militantes et son modèle coopératif. L\'agence de Thionville sert les sociétaires de Moselle avec des offres en assurance habitation, auto, santé et prévoyance. La MAIF est régulièrement classée parmi les entreprises préférées des Français pour sa qualité de service et son engagement solidaire. Elle recrute des profils commerciaux, gestion et digital.', 4, 5, 3, 0),
(25, 'Fenwick-Linde France', 1100, 'https://www.fenwick.fr', 'rh@fenwick.fr', '0387362000', 'Zone Industrielle de Terville', 'Leader européen des chariots élévateurs et de la logistique industrielle.', 'Fenwick-Linde est le leader européen de la manutention et des chariots élévateurs. Son agence lorraine, basée près de Thionville, accompagne des industriels et logisticiens dans la gestion de leur parc de chariots avec des contrats de maintenance, location longue durée et conseil en optimisation d\'entrepôts. L\'environnement technique est très porteur pour des profils en logistique, maintenance industrielle et commercial B2B.', 5, 5, 14, 0),
(26, 'Groupe SES (Sociétés d\'Economie Sociale)', 150, 'https://www.groupe-ses.fr', 'contact@groupe-ses.fr', '0387197000', '18 Rue des Atrébates', 'Structure de l\'économie sociale et solidaire gérant des services à la personne en Lorraine.', 'Le Groupe SES est un acteur de l\'économie sociale et solidaire en Lorraine. Il regroupe plusieurs associations et coopératives intervenant dans le champ des services à la personne, de la formation professionnelle et de l\'insertion par l\'activité économique. L\'organisation est engagée dans des valeurs de solidarité et d\'utilité sociale. Un contexte enrichissant pour des profils en RH, gestion associative et travail social.', 3, 5, 12, 0),
(27, 'Cosmétique Active France (L\'Oréal)', 700, 'https://www.loreal.com', 'recrutement.cosmetique@loreal.com', '0238699000', 'Zone Industrielle Saint-Marceau', 'Division de L\'Oréal spécialisée en cosmétique dermatologique et pharmaceutique.', 'Cosmétique Active France est la division de L\'Oréal dédiée aux produits dermatologiques et cosmétiques distribués en pharmacie. L\'usine d\'Orléans produit des marques emblématiques comme La Roche-Posay et Vichy. Elle intègre des procédés de fabrication avancés et un contrôle qualité rigoureux. Les stages portent sur la production, la qualité, le marketing et la logistique dans un environnement international stimulant.', 10, 6, 5, 0),
(28, 'Engie - Agence Orléans', 2500, 'https://www.engie.fr', 'contact.orleans@engie.fr', '0238692000', '15 Rue de la Poterne', 'Leader mondial de l\'énergie, avec une agence régionale active dans le Centre-Val de Loire.', 'Engie est un leader mondial de l\'énergie et des services aux bâtiments. Son agence d\'Orléans intervient sur des contrats de gestion énergétique, de maintenance d\'installations thermiques et d\'efficacité énergétique pour des bâtiments publics et privés de la région Centre-Val de Loire. Engie développe des solutions bas carbone avec un fort volet en énergies renouvelables.', 7, 6, 15, 0),
(29, 'Caisse d\'Epargne Loire-Centre', 1800, 'https://www.caisse-epargne.fr/loire-centre', 'contact@loire-centre.caisseepargne.fr', '0238780000', '7 Rue d\'Escures', 'Banque coopérative régionale servant les particuliers et professionnels du Centre-Val de Loire.', 'La Caisse d\'Epargne Loire-Centre est une banque coopérative ancrée dans le territoire du Centre-Val de Loire. Avec son siège à Orléans, elle dispose d\'un dense réseau d\'agences. Elle accompagne particuliers, professionnels et collectivités locales avec une offre complète de produits bancaires, d\'assurance et de gestion de patrimoine. Engagée dans la RSE, elle soutient activement les projets associatifs et solidaires de la région.', 8, 6, 3, 0),
(30, 'Nexter Systems (KNDS)', 1500, 'https://www.nexter-group.fr', 'recrutement@nexter-group.fr', '0238574000', 'Route de Gidy', 'Industriel de défense français, concepteur des chars Leclerc et véhicules blindés.', 'Nexter Systems, devenu KNDS avec son partenaire allemand KMW, est le principal fabricant français de systèmes terrestres de défense. Son site d\'Orléans est consacré à la maintenance et à la remise en service des chars Leclerc, VBCI et autres véhicules blindés. L\'entreprise recrute des ingénieurs, techniciens de maintenance et profils en gestion de projets industriels dans un secteur de pointe stratégique.', 6, 6, 10, 0),
(31, 'EDF - Direction Ile-de-France', 6000, 'https://www.edf.fr', 'recrutement@edf.fr', '0140421000', 'Tour EDF, 20 Place Paris La Défense', 'Premier producteur d\'électricité en France et acteur majeur de la transition énergétique.', 'EDF est le premier producteur d\'électricité en France et un acteur majeur de la transition énergétique mondiale. Sa Direction Ile-de-France, basée à La Défense, pilote des projets d\'envergure dans le nucléaire, les énergies renouvelables et les réseaux intelligents. Les stagiaires y rejoignent des équipes pluridisciplinaires sur des missions en ingénierie, gestion de projet, finance et digital.', 30, 7, 15, 0),
(32, 'Société Générale - Siège Social', 8000, 'https://www.societegenerale.com', 'stages@societegenerale.fr', '0142147000', 'Tour Société Générale, La Défense', 'L\'un des premiers groupes bancaires français et européens, présent dans 66 pays.', 'Société Générale est l\'un des premiers groupes bancaires européens, fondé en 1864. Son siège social, situé à La Défense, regroupe des équipes de banque de financement et d\'investissement, de gestion d\'actifs, de transformation digitale et de fonctions centrales. Chaque année, le groupe accueille plusieurs milliers de stagiaires et alternants sur des missions à haute valeur ajoutée. Un tremplin idéal pour une carrière dans la finance.', 50, 7, 3, 0),
(33, 'Publicis Groupe - Siège', 4000, 'https://www.publicisgroupe.com', 'recrutement@publicisgroupe.com', '0144434000', '133 Avenue des Champs-Elysées', 'Troisième groupe mondial de communication et de conseil en transformation marketing.', 'Publicis Groupe est le troisième groupe mondial de communication, publicité et conseil en transformation. Son siège parisien concentre les fonctions stratégiques, créatives et technologiques du groupe. Publicis abrite des agences emblématiques (Saatchi & Saatchi, Leo Burnett, Marcel) et des entités spécialisées en data, e-commerce et production de contenu. Les stages proposés couvrent la stratégie de marque, la data analytics, le digital et la créativité.', 25, 7, 5, 0),
(34, 'Accenture France', 7000, 'https://www.accenture.com/fr-fr', 'recrutement@accenture.fr', '0155778000', 'Tour Carpe Diem, La Défense', 'Leader mondial du conseil en management et de la transformation numérique.', 'Accenture est un leader mondial du conseil en management, de la technologie et de l\'externalisation de processus. Présent dans plus de 120 pays, son bureau parisien à La Défense est l\'un des plus importants d\'Europe. Les équipes accompagnent des entreprises du CAC40 et des institutions publiques dans leur transformation digitale, leur adoption de l\'IA et leurs projets cloud. Accenture est reconnu pour ses programmes d\'intégration et de formation des stagiaires.', 35, 7, 6, 0),
(35, 'Total Energies - Siège', 9000, 'https://www.totalenergies.com', 'stages@totalenergies.com', '0147444546', 'La Défense 6, 2 Place Jean Millier', 'Major pétrolière française en transformation vers les énergies renouvelables.', 'TotalEnergies est l\'une des plus grandes compagnies énergétiques mondiales, présente dans plus de 130 pays. Son siège à La Défense concentre les fonctions stratégiques, financières et de R&D. La compagnie opère dans le pétrole, le gaz, les énergies renouvelables (solaire, éolien) et l\'électricité. Les stages proposés sont très variés : géologie, ingénierie offshore, finance, trading, marketing et communication.', 40, 7, 15, 0),
(36, 'LVMH - Maison mère', 5000, 'https://www.lvmh.com', 'recrutement@lvmh.com', '0144133000', '22 Avenue Montaigne', 'Premier groupe mondial de produits de luxe avec 75 maisons de renommée mondiale.', 'LVMH Moët Hennessy Louis Vuitton est le numéro un mondial du luxe avec un portefeuille de 75 maisons dans la mode, la maroquinerie, les parfums, les montres, les vins et spiritueux et la distribution sélective. Le siège social à Paris coordonne les activités de marques iconiques telles que Louis Vuitton, Dior, Givenchy et Bulgari. Les stages au sein des équipes centrales portent sur la finance, le marketing de luxe, la supply chain et la communication.', 30, 7, 4, 0),
(37, 'Wiremold-Legrand - Tours', 600, 'https://www.legrand.fr', 'recrutement.tours@legrand.fr', '0247315000', 'Zone Industrielle Saint-Symphorien', 'Leader mondial des infrastructures électriques et numériques du bâtiment.', 'Legrand est le spécialiste mondial des infrastructures électriques et numériques du bâtiment. Son usine tourangelle fabrique des solutions de gestion des câbles, de protection électrique et d\'automatisation pour le résidentiel et le tertiaire. L\'entreprise est reconnue pour ses programmes d\'innovation et de développement durable. Les stages concernent la fabrication industrielle, la qualité, le développement produit et la gestion de la chaîne d\'approvisionnement.', 7, 8, 10, 0),
(38, 'Indre-et-Loire Habitat', 200, 'https://www.ilhabitat.fr', 'contact@ilhabitat.fr', '0247316100', '10 Allée du Nouveau Monde', 'Bailleur social de référence en Touraine, gérant un parc important de logements.', 'Indre-et-Loire Habitat est l\'office public de l\'habitat du département d\'Indre-et-Loire. Il gère un parc de plus de 20 000 logements sociaux répartis sur l\'ensemble du département. La structure investit dans la rénovation thermique, la construction neuve et la qualité de vie des locataires. Les stages portent sur la gestion de patrimoine immobilier, la réhabilitation, la gestion locative et la relation client.', 4, 8, 9, 0),
(39, 'STMicroelectronics - Tours', 2500, 'https://www.st.com', 'recrutement.tours@st.com', '0247440000', 'Zone Industrielle Saint-Egrève', 'Géant mondial des semi-conducteurs, avec un centre de R&D et fabrication à Tours.', 'STMicroelectronics est l\'un des plus grands fabricants mondiaux de semi-conducteurs. Son site de Tours héberge un centre de R&D et de fabrication de composants pour l\'automobile, l\'industrie et la communication. L\'entreprise développe des produits de pointe (microcontrôleurs, capteurs MEMS, circuits intégrés) et offre des stages en microélectronique, physique, automatismes et génie électrique dans un cadre international.', 12, 8, 11, 0),
(40, 'Colas Centre-Ouest', 800, 'https://www.colas.com', 'contact.centreouest@colas.com', '0247499500', '40 Rue des Bordiers', 'Filiale de Colas spécialisée dans les travaux routiers et l\'aménagement urbain en Centre-Val de Loire.', 'Colas est l\'un des leaders mondiaux dans la construction et la maintenance des infrastructures de transport. Son agence Centre-Ouest, basée à Tours, réalise des chantiers de voirie, d\'aménagement routier et de génie civil sur l\'ensemble du Centre-Val de Loire. Colas s\'inscrit dans une démarche d\'innovation avec des enrobés bas carbone et des matériaux recyclés. Les stages portent sur la conduite de chantier, l\'étude de prix et la gestion de projet BTP.', 6, 8, 7, 0),
(41, 'Leroy Somer (Nidec)', 1800, 'https://www.leroys.fr', 'rh@leroys.fr', '0545648000', '16 Avenue Président Allende', 'Leader mondial en moteurs électriques et générateurs industriels, fleuron charentais.', 'Leroy Somer, filiale du groupe japonais Nidec, est le leader mondial dans la conception et la fabrication de moteurs électriques, de variateurs de vitesse et d\'alternateurs. Son site historique d\'Angoulême abrite le siège européen et un centre R&D très actif. L\'entreprise exporte dans le monde entier et recrute régulièrement des ingénieurs, techniciens et gestionnaires sur des missions en électrotechnique, mécanique et développement commercial.', 10, 9, 10, 0),
(42, 'Nexans France - Charente', 500, 'https://www.nexans.fr', 'contact.charente@nexans.fr', '0545955500', 'Zone Industrielle Champniers', 'Fabricant mondial de câbles et solutions de connexion pour l\'énergie et l\'industrie.', 'Nexans est l\'un des leaders mondiaux de l\'industrie du câble. Son usine charentaise produit des câbles d\'énergie pour les réseaux de distribution électrique, les éoliennes et les infrastructures industrielles. L\'entreprise est engagée dans la transition vers les matériaux recyclables et les procédés bas carbone. Les stagiaires y interviennent en production, qualité, logistique et R&D matériaux.', 6, 9, 10, 0),
(43, 'DPDHL (DHL) - Entrepôt Angoulême', 400, 'https://www.dhl.com/fr-fr', 'recrutement.angers@dhl.com', '0545694500', 'Zone Logistique de Champniers', 'Leader mondial de la logistique et du transport express, avec un hub en Charente.', 'DHL est le leader mondial de la logistique et du courrier express. Son entrepôt d\'Angoulême est un hub régional gérant la distribution de colis et marchandises pour le Sud-Ouest. L\'entreprise investit dans la robotisation et l\'optimisation de ses entrepôts pour répondre à la croissance du e-commerce. Les stages portent sur la gestion d\'entrepôt, la planification logistique et l\'optimisation de flux.', 5, 9, 14, 0),
(44, 'Caisse d\'Epargne Aquitaine Poitou-Charentes', 2000, 'https://www.caisse-epargne.fr/aquitaine-poitou-charentes', 'contact@ceapc.fr', '0545391000', '3 Place du Champ de Mars', 'Banque coopérative régionale au service des habitants de la Nouvelle-Aquitaine.', 'La Caisse d\'Epargne Aquitaine Poitou-Charentes est une banque coopérative implantée dans un vaste territoire allant de la Gironde à la Charente. Son réseau d\'agences accompagne les particuliers, les professionnels et les collectivités avec des offres bancaires, d\'assurance et d\'investissement adaptées. La banque est engagée dans le financement de l\'économie sociale et solidaire et dans la transition énergétique.', 7, 9, 3, 0),
(45, 'Naval Group - Brest', 3000, 'https://www.navalgroup.com', 'recrutement@navalgroup.com', '0298221000', 'Rue Choiseul', 'Premier industriel naval européen de défense, constructeur de frégates et sous-marins.', 'Naval Group est le premier industriel naval de défense européen. Son site de Brest est l\'un des plus importants du groupe, dédié à la construction et à la maintenance de frégates, sous-marins et bâtiments de surface pour la Marine Nationale. L\'entreprise innove constamment dans des domaines tels que la propulsion navale, les systèmes d\'armes et le numérique embarqué. Les profils d\'ingénieurs, techniciens et gestionnaires y trouvent des missions passionnantes.', 15, 10, 10, 0),
(46, 'Ifremer - Centre de Brest', 800, 'https://www.ifremer.fr', 'contact.brest@ifremer.fr', '0298224000', 'Technopôle Brest-Iroise', 'Institut national de recherche pour l\'exploitation durable de la mer.', 'L\'Ifremer (Institut Français de Recherche pour l\'Exploitation de la Mer) est un organisme public de recherche dédié à la connaissance et à la gestion durable des océans. Son centre de Brest, le plus grand du pays, regroupe des laboratoires de pointe en océanographie physique, biologie marine, géosciences marines et technologies sous-marines. Les stages offerts concernent la recherche appliquée, l\'instrumentation marine, l\'analyse de données et l\'environnement.', 8, 10, 12, 0),
(47, 'Bolloré Logistics - Brest', 600, 'https://www.bollore-logistics.com', 'contact.brest@bollore-logistics.com', '0298804500', 'Port de Commerce de Brest', 'Filiale du groupe Bolloré, gestionnaire de terminaux portuaires et de logistique internationale.', 'Bolloré Logistics est un acteur majeur de la logistique internationale et du transport multimodal. Son agence de Brest gère des opérations portuaires, de fret maritime et de transit douanier pour des clients industriels et importateurs. L\'entreprise offre des stages dynamiques en exploitation portuaire, commerce international, douane et planification logistique dans un environnement maritime et international.', 6, 10, 14, 0),
(48, 'Bouygues Construction - Bretagne', 1500, 'https://www.bouygues-construction.com', 'contact.brest@bouygues-construction.com', '0298460000', '15 Rue Jean Jaurès', 'Acteur majeur du BTP en Bretagne, filiale du groupe Bouygues Construction.', 'Bouygues Construction est l\'un des leaders mondiaux de la construction. Son agence bretonne, basée à Brest, réalise des projets de logements, d\'ouvrages d\'art, de bâtiments tertiaires et d\'infrastructures pour la région. L\'entreprise innove avec des méthodes BIM, des matériaux bas carbone et des processus de construction hors-site. Les stages concernent la conduite de travaux, les études techniques, la qualité et la gestion contractuelle.', 8, 10, 7, 0),
(49, 'Renault - Usine du Mans', 2800, 'https://www.renaultgroup.com', 'recrutement.lemans@renault.com', '0243409000', 'Route de Laigné-en-Belin', 'Usine Renault spécialisée dans les boîtes de vitesses et organes de transmission.', 'L\'usine Renault du Mans est l\'un des sites industriels les plus importants du groupe en France. Spécialisée dans la production de boîtes de vitesses et d\'organes de transmission pour différents modèles de la gamme Renault et Nissan, elle emploie plusieurs milliers de personnes. Le site investit dans l\'automatisation et la transition vers les composants électriques. Les stages portent sur la production industrielle, la qualité, la maintenance et la gestion de projets.', 12, 11, 2, 0),
(50, '24h du Mans / Automobile Club de l\'Ouest (ACO)', 200, 'https://www.lemans.org', 'contact@lemans.org', '0243406600', '8 Place Luigi Chinetti', 'Organisateur des 24h du Mans, l\'une des compétitions automobiles les plus mythiques du monde.', 'L\'Automobile Club de l\'Ouest (ACO) organise les célèbres 24 Heures du Mans, considérées comme la course d\'endurance la plus prestigieuse au monde. La structure gère toute l\'organisation logistique, commerciale et médiatique de l\'événement ainsi que d\'autres courses du calendrier international. Les stages proposés concernent la communication, le marketing événementiel, la logistique et la gestion de partenariats.', 5, 11, 5, 0),
(51, 'MMA (Groupe Covéa) - Siège', 1500, 'https://www.mma.fr', 'recrutement@mma.fr', '0243214500', '14 Boulevard Marie et Alexandre Oyon', 'Assureur multi-risques majeur et siège social du groupe Covéa au Mans.', 'MMA est l\'une des grandes compagnies d\'assurances françaises, spécialisée dans la multi-risques habitation, auto et professionnels. Son siège social au Mans est le centre névralgique des activités de souscription, sinistres, actuariat et digital du groupe Covéa. MMA propose régulièrement des stages dans les domaines de l\'assurance, du droit, de la data science, de la relation client et des systèmes d\'information.', 10, 11, 3, 0),
(52, 'ICM - Ingénierie et Constructions Modulaires', 180, 'https://www.icm-modulaire.fr', 'contact@icm-modulaire.fr', '0243789000', 'ZA de la Marinière', 'Concepteur et fabricant de bâtiments modulaires pour le tertiaire, l\'industrie et le secteur public.', 'ICM est une PME sarthoise spécialisée dans la conception et la fabrication de bâtiments modulaires et de salles blanches pour les secteurs pharmaceutiques, agroalimentaires et industriels. Son bureau d\'études intègre des ingénieurs en structure, fluides et électricité. L\'entreprise exporte dans plusieurs pays européens et propose des stages techniques en bureau d\'études, production et commercial.', 4, 11, 7, 0),
(53, 'Lacoste - Site de fabrication', 900, 'https://www.lacoste.com', 'recrutement@lacoste.com', '0546345000', 'Route de Saintes', 'Marque internationale de mode sportswear, avec son site de confection charentais-maritime.', 'Lacoste est une marque de mode française mondialement connue pour son polo au crocodile. Son site de production charentais est l\'un des rares exemples de fabrication textile de haute qualité encore maintenu en France. L\'entreprise combine tradition artisanale et innovation textile pour ses collections haut de gamme. Les stages concernent la production, le contrôle qualité, la supply chain et le développement produit.', 7, 12, 4, 0),
(54, 'Alstom - Site de La Rochelle', 2000, 'https://www.alstom.com', 'recrutement.larochelle@alstom.com', '0546458000', 'Avenue de Bourgogne', 'Alstom est un leader mondial du transport ferroviaire qui conçoit, fabrique et maintient des trains, des métros et des tramways. Son usine de La Rochelle est l\'une des plus emblématiques du groupe, spécialisée dans la production de TGV et d\'automotrices. ', 'Alstom est un leader mondial du transport ferroviaire qui conçoit, fabrique et maintient des trains, des métros et des tramways. Son usine de La Rochelle est l\'une des plus emblématiques du groupe, spécialisée dans la production de TGV et d\'automotrices. La transition vers le ferroviaire décarbonné place Alstom au cœur des enjeux de mobilité durable. Les stages couvrent l\'ingénierie, la production industrielle, la qualité et la gestion de projets.', 15, 12, 2, 0),
(55, 'Suez - Eau & Assainissement Charentes', 350, 'https://www.suez.com', 'contact.charentes@suez.com', '0546517000', '10 Rue Papin', 'Acteur mondial de la gestion durable de l\'eau et des déchets, présent en Charente-Maritime.', 'Suez est l\'un des leaders mondiaux de la gestion de l\'eau, de l\'assainissement et des déchets. Son agence Charentes gère les services d\'eau potable et d\'assainissement pour plusieurs communes de la région. L\'entreprise développe des solutions d\'économie circulaire et de préservation des ressources naturelles. Les stages portent sur le traitement de l\'eau, l\'exploitation des réseaux, l\'environnement et la gestion de la relation client.', 5, 12, 15, 0),
(56, 'Groupe Idea (Immobilier)', 120, 'https://www.groupe-idea.fr', 'contact@groupe-idea.fr', '0546410000', '12 Cours du Temple', 'Promoteur et gestionnaire immobilier régional actif sur le littoral atlantique.', 'Groupe Idea est un promoteur immobilier régional spécialisé dans la construction de logements neufs, de résidences de tourisme et d\'immeubles de bureaux sur le littoral atlantique. L\'entreprise développe des projets durables en intégrant des normes environnementales ambitieuses (BBC, HQE). Ses équipes proposent des stages en développement foncier, gestion de programmes immobiliers, vente et marketing.', 3, 12, 9, 0),
(57, 'Airbus Atlantic - Nantes', 5500, 'https://www.airbus.com', 'recrutement.nantes@airbus.com', '0240841000', 'Route de Gachet', 'Filiale d\'Airbus spécialisée dans les structures aérostructures et l\'assemblage d\'aéronefs.', 'Airbus Atlantic est la filiale industrielle d\'Airbus dédiée aux aérostructures. Son site de Nantes, l\'un des plus importants du groupe, fabrique des fuselages, nacelles et mâts réacteurs pour les familles A320, A330 et A350. L\'entreprise est à la pointe des matériaux composites et des procédés de fabrication additive. Les stages sont très recherchés en ingénierie aéronautique, qualité, industrialisation et supply chain.', 20, 13, 2, 0),
(58, 'Banque Populaire Grand Ouest', 2200, 'https://www.bpgo.fr', 'contact@bpgo.fr', '0240203000', '15 Boulevard Guist\'hau', 'Banque coopérative majeure en Bretagne et Pays de la Loire, au service des professionnels.', 'La Banque Populaire Grand Ouest est une banque coopérative issue de la fusion de plusieurs caisses régionales. Elle est un partenaire financier majeur des particuliers, professionnels et entreprises des régions Bretagne et Pays de la Loire. La banque accompagne la création d\'entreprises, les projets immobiliers et la gestion d\'actifs. Elle développe activement ses offres numériques et son engagement en faveur de l\'économie locale.', 12, 13, 3, 0),
(59, 'Fnac Darty - Direction Régionale Ouest', 600, 'https://www.fnacdarty.com', 'recrutement.ouest@fnacdarty.com', '0240434000', '20 Place du Commerce', 'Leader européen de la distribution spécialisée en produits culturels et électronique.', 'Fnac Darty est le leader européen de la distribution spécialisée en produits culturels, informatiques, électroniques et électroménager. Sa direction régionale Ouest, basée à Nantes, supervise les magasins des Pays de la Loire et de Bretagne. La structure est en forte transformation digitale avec le développement du click & collect, du marketplaces et des services omnicanaux. Les stages portent sur le commerce, le digital, la logistique et le management.', 8, 13, 4, 0),
(60, 'Keolis - Tan (Transport de l\'Agglomération Nantaise)', 1500, 'https://www.tan.fr', 'contact@tan.fr', '0240295200', '3 Rue Bellier', 'Opérateur du réseau de transports publics de Nantes Métropole (tramway, busway, bus).', 'TAN est le réseau de transports publics de Nantes Métropole, exploité par Keolis. Il s\'agit de l\'un des réseaux de tramway les plus développés de France avec plusieurs lignes interconnectées. La TAN gère également des lignes de bus, de busway et de navettes fluviales. L\'entreprise investit dans des véhicules propres et des systèmes d\'information voyageurs intelligents. Les stages couvrent la gestion des transports, le marketing territorial et la maintenance des véhicules.', 7, 13, 14, 0),
(61, 'Nantes Métropole Habitat', 400, 'https://www.nantesmetropolehab.fr', 'contact@nantesmetropolehab.fr', '0240412020', '8 Rue de la Baume', 'Bailleur social référent de la métropole nantaise, gérant un parc de logements sociaux.', 'Nantes Métropole Habitat est l\'office public de l\'habitat de Nantes Métropole. Il gère plus de 28 000 logements sociaux et développe activement de nouveaux programmes dans le cadre du Plan Local de l\'Habitat. L\'office investit dans la rénovation énergétique de son parc et dans des politiques d\'inclusion sociale. Les stages portent sur la gestion immobilière, la réhabilitation, la maîtrise d\'ouvrage et la relation locataire.', 6, 13, 9, 0),
(62, 'Chantiers de l\'Atlantique', 3500, 'https://www.chantiersatlantique.com', 'recrutement@chantiersatlantique.com', '0240667777', 'Boulevard de la Légion d\'Honneur', 'Constructeur naval de renommée mondiale, créateur des plus grands paquebots de croisière.', 'Chantiers de l\'Atlantique est le fleuron de la construction navale française. Basés à Saint-Nazaire, les chantiers construisent les plus grands paquebots de croisière du monde, dont les célèbres Oasis of the Seas. Le site est un concentré d\'expertise en ingénierie navale, en mécanique de précision et en intégration de systèmes complexes. Les stages proposés sont uniques au monde : ingénierie navale, gestion de projets monumentaux, logistique de construction.', 20, 14, 2, 0),
(63, 'Donges Raffinerie (TotalEnergies)', 800, 'https://www.totalenergies.com', 'contact.donges@totalenergies.com', '0240456000', 'Zone Industrielle de Donges', 'Raffinerie TotalEnergies parmi les plus importantes de France, sur l\'estuaire de la Loire.', 'La Raffinerie de Donges est l\'une des plus grandes raffineries de TotalEnergies en France. Elle traite plusieurs millions de tonnes de pétrole brut par an pour produire carburants, fioul et produits spéciaux. Le site modernise ses installations pour intégrer des biocarburants et réduire son empreinte carbone. Les stages en génie des procédés, QHSE, instrumentation et mécanique y sont particulièrement enrichissants.', 8, 14, 15, 0),
(64, 'GE Renewable Energy - Saint-Nazaire', 700, 'https://www.ge.com/renewableenergy', 'recrutement@ge-renergy.com', '0240533000', 'Parc d\'Activités de la Brière', 'Fabricant mondial d\'éoliennes offshore, avec une usine nazairienne en plein essor.', 'GE Renewable Energy est une filiale de General Electric spécialisée dans la fabrication et l\'installation d\'éoliennes offshore. Son usine de Saint-Nazaire produit des nacelles pour les champs éoliens en mer, dans le cadre du développement massif de l\'éolien offshore français. L\'entreprise est au cœur des enjeux de la transition énergétique. Les stages concernent la production industrielle, l\'ingénierie des composites, la qualité et la gestion de projets.', 8, 14, 15, 0),
(65, 'Altran (Capgemini Engineering) - Aix', 4000, 'https://www.capgemini.com/fr-fr/services/engineering', 'recrutement.aix@capgemini.com', '0442597000', 'Pôle d\'Activités d\'Aix-en-Provence', 'Leader mondial de l\'ingénierie et du conseil en R&D, racheté par Capgemini.', 'Altran, devenu Capgemini Engineering, est le leader mondial du conseil en ingénierie et R&D. Son bureau d\'Aix-en-Provence accompagne des clients dans les secteurs aéronautique, automobile, énergie et défense. Les équipes de l\'agence provençale travaillent sur des projets innovants en systèmes embarqués, IA, simulation numérique et conception mécanique. Un environnement idéal pour des ingénieurs en quête de défis techniques.', 10, 15, 6, 0),
(66, 'Sanofi - Marcy-l\'Etoile Provence', 1200, 'https://www.sanofi.com', 'recrutement.aix@sanofi.com', '0442973000', 'Zone Industrielle Les Milles', 'Second groupe pharmaceutique français, avec un site de production en Provence.', 'Sanofi est l\'un des premiers groupes pharmaceutiques mondiaux. Son site provençal, localisé aux Milles près d\'Aix-en-Provence, gère la production et le conditionnement de médicaments destinés aux marchés européens. L\'entreprise est engagée dans des programmes de santé publique globale et d\'innovation thérapeutique. Les stages couvrent la production pharmaceutique, la réglementation, la qualité et la supply chain.', 8, 15, 13, 0),
(67, 'Imerys - Direction Générale', 600, 'https://www.imerys.com', 'recrutement@imerys.com', '0442162000', 'Les Florides II, Route d\'Avignon', 'Leader mondial des minéraux industriels pour les secteurs de la construction, de la céramique et du papier.', 'Imerys est le leader mondial des solutions minérales pour l\'industrie. Son siège, basé à Aix-en-Provence, pilote des activités dans plus de 40 pays. L\'entreprise exploite et transforme des minéraux (kaolin, talc, carbonate de calcium) pour les industries de la construction, de la céramique et des polymères. Les stages portent sur la géologie, la chimie des matériaux, le marketing B2B et la gestion de la chaîne d\'approvisionnement.', 7, 15, 10, 0),
(68, 'Pichet Groupe - Résidence Services', 350, 'https://www.pichet.fr', 'recrutement@pichet.fr', '0442260000', '35 Cours Mirabeau', 'Promoteur immobilier régional actif dans le résidentiel et les résidences services sur la Côte d\'Azur.', 'Pichet est l\'un des premiers groupes immobiliers indépendants français. Son agence provençale développe des programmes de logements neufs, de résidences étudiantes et de résidences seniors. La société est reconnue pour la qualité architecturale de ses réalisations et son engagement dans la construction durable. Les stages portent sur le développement foncier, la gestion de programmes, la vente immobilière et le marketing.', 4, 15, 9, 0),
(69, 'STMicroelectronics - Grenoble', 3500, 'https://www.st.com', 'recrutement.grenoble@st.com', '0476588000', '850 Rue Jean Monnet', 'Centre de R&D et de fabrication mondial de ST en semi-conducteurs à Crolles/Grenoble.', 'STMicroelectronics est l\'un des leaders mondiaux des semi-conducteurs. Son site de la région grenobloise est l\'un des plus importants du groupe au niveau mondial, avec un centre de R&D très actif et des lignes de fabrication 300mm à la pointe. ST collabore avec le CEA-Leti et de nombreuses start-ups sur des technologies de rupture (MEMS, IoT, SiC). Les stages sont extrêmement valorisants pour les profils en microélectronique et physique.', 15, 16, 11, 0),
(70, 'Schneider Electric - Siège Mondial', 8000, 'https://www.se.com/fr', 'recrutement@schneider-electric.com', '0476576000', '35 Rue Joseph Monier', 'Leader mondial de la gestion de l\'énergie et des automatismes industriels.', 'Schneider Electric est le leader mondial de la gestion de l\'énergie et des automatismes industriels. Avec son siège mondial à Rueil-Malmaison et son campus d\'innovation à Grenoble, l\'entreprise développe des solutions pour rendre l\'énergie plus fiable, sûre et efficace. Ses offres couvrent les datacenters, les bâtiments intelligents, l\'industrie et les réseaux électriques. Les stages proposés sont au croisement du hardware, du software et du conseil.', 20, 16, 11, 0),
(71, 'CEA-Tech Grenoble (Leti)', 4500, 'https://www.cea.fr', 'recrutement.leti@cea.fr', '0438780000', '17 Rue des Martyrs', 'Centre d\'innovation technologique du CEA, référence mondiale en micro et nanotechnologies.', 'Le CEA-Leti est un institut de recherche technologique appartenant au CEA. Basé à Grenoble, il est l\'un des plus grands centres européens de recherche appliquée en micro et nanotechnologies. Le Leti collabore avec de grandes entreprises industrielles et des start-ups pour accélérer l\'innovation en microélectronique, photonique, intelligence artificielle et santé numérique. Les stages et thèses proposés y sont d\'un niveau exceptionnel.', 20, 16, 6, 0),
(72, 'Rossignol Group', 800, 'https://www.rossignol.com', 'rh@rossignol.com', '0476458000', 'Rue de la Chartreuse', 'Leader mondial des équipements de sports de glisse, marque emblématique des Alpes.', 'Le Groupe Rossignol est l\'un des leaders mondiaux de l\'industrie des sports de glisse, avec des marques iconiques telles que Rossignol, Dynastar, Lange et Look. Son siège et son centre de design sont basés dans les Alpes. L\'entreprise innove constamment pour améliorer les performances de ses skis, chaussures et fixations. Les stages concernent le design produit, l\'ingénierie des matériaux composites, le marketing sportif et le commerce international.', 8, 16, 10, 0);
INSERT INTO `ENTREPRISE` (`entreprise_id`, `entreprise_nom`, `entreprise_taille`, `entreprise_siteweb`, `entreprise_email`, `entreprise_telephone`, `entreprise_rue`, `entreprise_extrait`, `entreprise_presentation`, `entreprise_nb_stagiaires`, `localite_id`, `secteur_id`, `entreprise_archive`) VALUES
(73, 'Sanofi - Lyon', 2800, 'https://www.sanofi.com', 'recrutement.lyon@sanofi.com', '0472742000', '1 Avenue Pierre Brossolette', 'Site industriel et de R&D de Sanofi, l\'un des plus importants du groupe en Europe.', 'Sanofi est l\'un des premiers groupes pharmaceutiques mondiaux. Son site de Lyon est l\'un des plus emblématiques, avec des activités de production de vaccins, d\'anticorps et de médicaments biologiques. Le site abrite également un important centre de R&D en immunologie et maladies infectieuses. Les stages y sont particulièrement prisés en biologie, chimie, génie des procédés, qualité et affaires réglementaires.', 20, 17, 13, 0),
(74, 'Infopro Digital', 1200, 'https://www.infopro-digital.com', 'recrutement@infopro-digital.com', '0472102000', '85 Avenue de la Libération', 'Leader des médias professionnels et des données B2B en France.', 'Infopro Digital est le leader des médias professionnels, des événements B2B et de la data en France. Le groupe édite des titres de référence (L\'Usine Nouvelle, Le Moniteur, L\'Argus de l\'assurance) et organise des salons reconnus. Son pôle data fournit des informations et analyses à des professionnels de nombreux secteurs. Les stages en journalisme B2B, marketing digital, data et événementiel y sont très formateurs.', 8, 17, 5, 0),
(75, 'GL Events', 2500, 'https://www.gl-events.com', 'recrutement@gl-events.com', '0472307000', '59 Quai Rambaud', 'Groupe international leader dans l\'organisation d\'événements et la gestion de lieux.', 'GL Events est un groupe mondial spécialisé dans l\'organisation d\'événements professionnels et grand public, et dans la gestion de centres de congrès et d\'expositions. Basé à Lyon, le groupe opère dans plus de 20 pays et gère des sites emblématiques comme Eurexpo et le Palais des Congrès de Lyon. Les stages en logistique événementielle, communication, marketing et gestion commerciale y sont très enrichissants.', 10, 17, 5, 0),
(76, 'Groupe SEB - Siège', 2000, 'https://www.groupeseb.com', 'recrutement@groupeseb.com', '0472189000', 'Les Quatre M, Route de Revel', 'Leader mondial du petit équipement domestique, créateur de marques iconiques.', 'Le Groupe SEB est le leader mondial du petit équipement domestique avec un portefeuille de marques emblématiques : Tefal, Moulinex, Rowenta, Krups, WMF. Son siège mondial, basé en région lyonnaise, coordonne les activités R&D, marketing, supply chain et digital du groupe. SEB est reconnu pour son modèle d\'innovation, basé sur un investissement R&D important et une politique de développement durable ambitieuse.', 15, 17, 10, 0),
(77, 'BioMérieux', 3200, 'https://www.biomerieux.com', 'recrutement@biomerieux.com', '0478874000', 'Chemin de l\'Orme', 'Leader mondial du diagnostic in vitro, pionnier de la médecine de précision.', 'bioMérieux est un leader mondial du diagnostic in vitro (DIV). Fondé à Lyon, le groupe développe et commercialise des tests de diagnostic microbiologique et moléculaire pour des applications médicales et industrielles. Sa R&D très active mobilise des centaines de chercheurs à Marcy-l\'Étoile. Les stages en biologie, chimie analytique, génie logiciel et marketing international y sont très prisés dans un contexte scientifique d\'excellence.', 12, 17, 13, 0),
(78, 'Vinci Autoroutes - Direction Rhône-Alpes', 1800, 'https://www.vinci-autoroutes.com', 'contact.rhonealpes@vinci-autoroutes.com', '0472597000', '2 Place René Gomès', 'Opérateur d\'autoroutes et gestionnaire d\'infrastructures de transport en Rhône-Alpes.', 'Vinci Autoroutes est le premier opérateur d\'autoroutes en France avec un réseau de plusieurs milliers de kilomètres. Sa direction Rhône-Alpes gère les concessions ASF et Escota dans la région. L\'entreprise investit dans la sécurité des usagers, la fluidification du trafic et les mobilités alternatives (bornes électriques, covoiturage). Les stages portent sur l\'exploitation autoroutière, le génie civil, l\'environnement et la communication.', 8, 17, 14, 0),
(79, 'Amadeus IT Group', 3500, 'https://www.amadeus.com', 'recrutement@amadeus.com', '0493289000', '485 Route du Pin Montard', 'Leader mondial des technologies pour le voyage et le tourisme.', 'Amadeus est le leader mondial des solutions informatiques pour le secteur du voyage. Son campus de Sophia Antipolis, proche de Nice, est l\'un des plus importants centres de R&D du groupe au monde. Les équipes développent des plateformes de réservation de vols, d\'hôtels et de services voyageurs utilisées par des milliers de compagnies aériennes et d\'agences. Les stages en développement logiciel, UX, data science et product management y sont très recherchés.', 15, 18, 11, 0),
(80, 'CNRS - Observatoire de la Côte d\'Azur', 600, 'https://www.oca.eu', 'contact@oca.eu', '0492003000', 'Boulevard de l\'Observatoire', 'Unité de recherche astronomique et géophysique de renommée internationale sur la Côte d\'Azur.', 'L\'Observatoire de la Côte d\'Azur (OCA) est une unité de recherche astronomique et géophysique sous tutelle conjointe du CNRS et de l\'Université Côte d\'Azur. Il réunit des équipes de chercheurs de renommée internationale sur des thématiques allant de la mécanique céleste à la géodésie spatiale. L\'OCA offre des stages en astrophysique, traitement du signal, instrumentation et modélisation numérique dans un cadre unique.', 5, 18, 12, 0),
(81, 'Elior Group - Côte d\'Azur', 1200, 'https://www.elior.fr', 'contact.ca@elior.fr', '0493218000', '2 Avenue Thiers', 'Acteur majeur de la restauration collective et des services, présent sur toute la Riviera.', 'Elior Group est l\'un des leaders mondiaux de la restauration collective. Son agence Côte d\'Azur gère des concessions de restauration dans des entreprises, hôpitaux, établissements scolaires et sites touristiques de la région. L\'entreprise développe des offres de restauration de qualité, durables et adaptées aux différents convives. Les stages concernent la gestion de restaurants collectifs, le management d\'équipes et la relation client.', 6, 18, 8, 0),
(82, 'Club Med - Direction Méditerranée', 800, 'https://www.clubmed.fr', 'recrutement@clubmed.fr', '0493188000', '40 Boulevard Dubouchage', 'Pionnier du concept de vacances tout compris, avec une direction régionale sur la Côte d\'Azur.', 'Club Med est le créateur du concept de vacances tout compris et l\'un des leaders du tourisme haut de gamme. Sa direction Méditerranée, basée à Nice, supervise des villages sur la Riviera et en Corse. L\'entreprise recrute des profils passionnés par l\'hospitalité et le service client. Les stages proposent des expériences immersives en hôtellerie, animation, marketing touristique et revenue management dans un cadre de rêve.', 10, 18, 8, 0),
(83, 'Groupe Ginestet (Vins de Bordeaux)', 400, 'https://www.ginestet.fr', 'contact@ginestet.fr', '0556481200', '19 Avenue de Fontenilles', 'Négociant et producteur viticole incontournable du vignoble bordelais.', 'Le Groupe Ginestet est l\'un des principaux négociants du vignoble de Bordeaux avec des châteaux en propre et une activité de négoce étendue. L\'entreprise exporte ses vins dans plus de 50 pays et mise sur des pratiques viticoles responsables. Les stages proposés concernent l\'œnologie, le commerce international du vin, le marketing viticole et la gestion de cave.', 5, 19, 1, 0),
(84, 'Thalès Avionique - Bordeaux', 2500, 'https://www.thalesgroup.com', 'recrutement.bordeaux@thalesgroup.com', '0556366000', 'Avenue Louis Breguet, Mérignac', 'Site d\'excellence de Thalès en systèmes avioniques et navigation aérienne.', 'Thales est un groupe international de technologies de défense, aérospatial et sécurité. Son site de Mérignac, près de Bordeaux, est spécialisé dans les systèmes avioniques (navigation, affichage, électronique de vol) pour les avions civils et militaires. Les équipes de Bordeaux contribuent à des programmes aéronautiques mondiaux. Les stages en avionique, génie électronique, systèmes embarqués et gestion de projets y sont très valorisants.', 12, 19, 2, 0),
(85, 'Inno TSD (groupe Bridgestone)', 900, 'https://www.bridgestone.eu', 'contact.bordeaux@bridgestone.eu', '0556348000', 'Zone Industrielle de Tresses', 'Usine française du leader mondial des pneumatiques, spécialisée en pneus agricoles et industriels.', 'Bridgestone est le numéro un mondial du pneumatique. Son usine de la région bordelaise produit des pneumatiques pour engins agricoles, de construction et industriels. L\'entreprise investit dans des procédés de vulcanisation innovants et dans la réduction de son empreinte environnementale. Les stages en production industrielle, qualité, maintenance et R&D matériaux offrent une expérience concrète dans un environnement de grande industrie.', 7, 19, 2, 0),
(86, 'Cdiscount (Casino Group) - Siège', 2000, 'https://www.cdiscount.com', 'recrutement@cdiscount.com', '0556995300', '120-126 Quai de Bacalan', 'Leader du e-commerce en France, avec son siège social à Bordeaux.', 'Cdiscount est l\'un des leaders du commerce en ligne en France, avec un catalogue de millions de références dans tous les univers. Filiale du Groupe Casino, son siège social est à Bordeaux. La société est un acteur technologique majeur, avec des équipes de data science, logistique, développement et marketing digital très actives. Les stages proposés couvrent tous les métiers du e-commerce, de la data, de la supply chain et du marketing.', 15, 19, 4, 0),
(87, 'Bordeaux Métropole', 1200, 'https://www.bordeaux-metropole.fr', 'contact@bordeaux-metropole.fr', '0556997900', 'Esplanade Charles de Gaulle', 'Collectivité territoriale gérant l\'aménagement et les services publics de la métropole bordelaise.', 'Bordeaux Métropole est la communauté urbaine regroupant 28 communes autour de Bordeaux. Elle gère des compétences majeures : transports (TBM), urbanisme, eau, déchets et développement économique. La collectivité mène des projets urbains ambitieux dont Bordeaux Euratlantique, le quartier d\'affaires en cours de développement. Les stages portent sur l\'urbanisme, le génie civil, la gestion de projets, les politiques publiques et la communication territoriale.', 8, 19, 12, 0),
(88, 'Sanofi Pasteur - Montpellier', 1800, 'https://www.sanofi.com', 'recrutement.montpellier@sanofi.com', '0467102000', '1541 Boulevard Bel Air', 'Site de production de vaccins et produits biologiques de Sanofi en Occitanie.', 'Sanofi Pasteur est la division vaccins de Sanofi. Son site de Montpellier est un pôle de production et de R&D en immunologie. L\'entreprise développe et fabrique des vaccins contre la grippe, la méningite et d\'autres maladies infectieuses. Les stages en biologie, virologie, génie des procédés biotechnologiques et affaires réglementaires sont très prisés dans cet environnement scientifique d\'excellence.', 10, 20, 13, 0),
(89, 'IBM France - Centre d\'Innovation', 2500, 'https://www.ibm.com/fr-fr', 'recrutement.montpellier@ibm.fr', '0467208000', 'Parc Club du Millénaire', 'Centre d\'excellence d\'IBM en intelligence artificielle, cloud et services numériques.', 'IBM est l\'un des géants mondiaux de l\'informatique et du conseil technologique. Son centre de Montpellier est un hub d\'innovation reconnu sur l\'IA, le cloud hybride et les services managés. Les équipes développent des solutions pour de grands comptes dans les secteurs de la finance, de la santé et de l\'industrie. Les stages en développement logiciel, cloud, data science et consulting y sont extrêmement valorisants.', 15, 20, 11, 0),
(90, 'Decathlon - Entrepôt Sud', 800, 'https://www.decathlon.fr', 'recrutement.sud@decathlon.fr', '0467647000', 'Route de la Mer', 'Leader mondial du commerce d\'articles de sport, avec un entrepôt et magasin phare.', 'Decathlon est le leader mondial de la distribution d\'articles de sport avec ses propres marques (Quechua, Btwin, Domyos). Son entrepôt régional et ses équipes commerciales du sud de la France, basés près de Montpellier, gèrent l\'approvisionnement et la distribution pour toute la région. Les stages concernent la logistique, le commerce, le marketing produit et le sport management dans un univers passionné et dynamique.', 8, 20, 4, 0),
(91, 'Agropolis International', 200, 'https://www.agropolis.fr', 'contact@agropolis.fr', '0467047500', '1000 Avenue Agropolis', 'Pôle mondial de compétences en agriculture, alimentation et biodiversité à Montpellier.', 'Agropolis International est un réseau unique au monde qui rassemble à Montpellier plus de 3400 chercheurs travaillant sur les sciences du vivant, l\'agriculture tropicale et la biodiversité. Ses membres incluent des organismes de recherche de renom (CIRAD, INRAE, IRD). Agropolis facilite les partenariats entre la recherche, les collectivités et les entreprises. Les stages portent sur la communication scientifique, la coordination de projets et les politiques agricoles.', 4, 20, 12, 0),
(92, 'Total Energies - Pau (TEPA)', 2200, 'https://www.totalenergies.com', 'contact.pau@totalenergies.com', '0559835000', 'Avenue Larribau', 'Direction E&P (Exploration-Production) de TotalEnergies pour l\'Europe et l\'Asie centrale.', 'TotalEnergies Pau est la direction régionale chargée de l\'exploration et la production d\'hydrocarbures pour l\'Europe et l\'Asie centrale. Ce centre de compétences mondiale regroupe des ingénieurs de forage, de géologie, de géophysique et de gestion des réservoirs. C\'est l\'un des foyers d\'expertise technique les plus reconnus de l\'industrie pétrolière mondiale. Les stages y sont de très haute qualité pour les ingénieurs en sciences de la Terre et génie pétrolier.', 12, 21, 15, 0),
(93, 'Turbomeca (Safran Helicopter Engines)', 2800, 'https://www.safran-helicopter-engines.com', 'recrutement@safran-helicopter-engines.com', '0559124000', 'Avenue Joseph Szydlowski', 'Leader mondial des moteurs d\'hélicoptères, fleuron de l\'industrie aéronautique béarnaise.', 'Safran Helicopter Engines (anciennement Turbomeca) est le leader mondial dans la conception et la fabrication de turbines pour hélicoptères. Son site de Bordes, proche de Pau, est le siège mondial du groupe et abrite son cœur industriel et son centre R&D. Les moteurs Arrius, Ardiden et Makila propulsent des hélicoptères civils et militaires dans le monde entier. Les stages en turbomachines, matériaux, thermodynamique et génie industriel y sont uniques.', 15, 21, 2, 0),
(94, 'Société Pau Béarn Pyrénées Tourisme', 80, 'https://www.tourisme-pyrenees-pau.com', 'contact@pau-pyrenees.com', '0559028400', 'Allée Alfred de Musset', 'Agence de développement touristique pour la destination Béarn-Pyrénées.', 'Pau Béarn Pyrénées Tourisme est l\'agence officielle de promotion touristique du territoire béarnais. Elle assure le marketing de la destination, l\'animation des sites touristiques et l\'accueil des visiteurs. La richesse du territoire (Pyrénées, villes d\'art, gastronomie, sports outdoor) offre un contexte stimulant. Les stages en tourisme, communication digitale, animation et développement local y sont très variés.', 3, 21, 8, 0),
(95, 'Airbus - Siège Monde', 8000, 'https://www.airbus.com', 'stages@airbus.com', '0561931000', '2 Rond-Point Emile Dewoitine', 'Premier avionneur européen et deuxième mondial, créateur de l\'A320, A330, A350 et A380.', 'Airbus est le premier avionneur européen et l\'un des deux leaders mondiaux de la construction aéronautique. Son siège mondial est basé à Toulouse. L\'entreprise conçoit et produit des avions commerciaux pour les compagnies aériennes du monde entier. L\'innovation en matériaux composites, systèmes de propulsion hybride et digitalisation de la supply chain est au cœur de sa stratégie. Les stages chez Airbus sont parmi les plus prisés au monde pour les ingénieurs.', 50, 22, 2, 0),
(96, 'Météo-France - Siège Social', 1800, 'https://www.meteofrance.fr', 'contact@meteofrance.fr', '0561079000', '1 Quai Branly', 'Service météorologique national, référence en prévision et climatologie.', 'Météo-France est le service météorologique et climatologique national de la France. Son siège, basé à Toulouse, regroupe les équipes de prévision numérique du temps, de climatologie et de recherche en météorologie. L\'organisation exploite des supercalculateurs parmi les plus puissants d\'Europe pour modéliser l\'atmosphère. Les stages en météorologie, océanographie, informatique scientifique et communication de crise sont très enrichissants.', 8, 22, 12, 0),
(97, 'Motul - Distribution Sud-Ouest', 350, 'https://www.motul.com', 'contact.so@motul.com', '0561351000', 'Zone Industrielle de l\'Agasse', 'Fabricant de lubrifiants haute performance pour l\'automobile, la moto et l\'industrie.', 'Motul est une entreprise française fondée en 1853, spécialisée dans les lubrifiants haute performance pour l\'automobile, la moto et l\'industrie. Sa notoriété dans le monde de la compétition (24h du Mans, MotoGP, Le Mans Classic) lui confère une image de marque exceptionnelle. L\'agence Sud-Ouest gère la distribution et le marketing pour la région. Les stages en marketing sportif, commercial B2B et gestion logistique y sont passionnants.', 4, 22, 5, 0),
(98, 'Pierre Fabre - Siège & Labo', 5000, 'https://www.pierre-fabre.com', 'recrutement@pierre-fabre.com', '0534505000', '45 Place Abel Gance', 'Groupe pharmaceutique et dermo-cosmétique français indépendant, ancré en Occitanie.', 'Pierre Fabre est le deuxième groupe pharmaceutique français indépendant. Il développe et commercialise des médicaments de spécialité et des produits dermo-cosmétiques reconnus (A-Derma, Ducray, Eau Thermale Avène). Son siège et ses principaux laboratoires sont ancrés en Occitanie. Le groupe est à 100% détenu par la Fondation Pierre Fabre. Les stages portent sur la pharmacologie, la dermo-cosmétologie, le marketing santé et la réglementation internationale.', 15, 22, 13, 0),
(99, 'CNES - Centre National d\'Etudes Spatiales', 2500, 'https://www.cnes.fr', 'recrutement@cnes.fr', '0561278000', '18 Avenue Edouard Belin', 'Agence spatiale nationale française, créatrice d\'Ariane, pilote des missions scientifiques.', 'Le CNES est l\'agence spatiale française. Son centre de Toulouse est le plus important du pays avec des activités de maîtrise d\'ouvrage de satellites, de systèmes de lancement et d\'applications spatiales. Le CNES collabore avec l\'ESA et les grandes agences spatiales mondiales. Les stages proposés sont exceptionnels pour les ingénieurs en aérospatial, optique, mécanique, télécommunications et traitement d\'images.', 20, 22, 6, 0),
(100, 'Airbus Defence and Space', 5000, 'https://www.airbus.com/space.html', 'recrutement.defence@airbus.com', '0561931500', '31 Rue des Cosmonautes', 'Entité Airbus spécialisée dans les systèmes de défense, la surveillance et les technologies spatiales.', 'Airbus Defence and Space est la division de défense, aérospatiale et sécurité du groupe Airbus. Son site toulousain, l\'un des plus importants du groupe, développe des satellites d\'observation et de communication, des drones militaires et des systèmes de cybersécurité. L\'entité travaille pour des clients gouvernementaux et institutionnels à travers le monde. Les stages couvrent des domaines de pointe : optique spatiale, communications par satellite, cyberdéfense et intelligence artificielle.', 25, 22, 2, 0),
(101, 'Bonduelle - Siège Social', 1500, 'https://www.bonduelle.com', 'recrutement@bonduelle.fr', '0321243000', 'La Woestyne, Renescure', 'Leader mondial des légumes transformés, fleuron de l\'agroalimentaire du Nord.', 'Bonduelle est le leader mondial de la transformation de légumes pour la conservation (boîtes, surgelés, frais). Ses racines sont dans le Nord-Pas-de-Calais, proche d\'Arras. Le groupe exporte dans plus de 100 pays avec des usines sur 5 continents. Bonduelle est engagé dans un modèle agricole durable et une politique RSE ambitieuse. Les stages couvrent l\'agroalimentaire, la qualité, le marketing, la logistique et les achats.', 10, 23, 1, 0),
(102, 'Norauto - Siège et Centre de Distribution', 1200, 'https://www.norauto.fr', 'recrutement@norauto.fr', '0321243500', 'Nœud Autoroutier A1-A26, Tilloy-lès-Mofflaines', 'Leader français du service automobile, avec son siège et entrepôt central dans l\'Artois.', 'Norauto est le leader français du centre auto, avec plus de 400 centres en France et une présence européenne croissante. Son siège social et son centre de distribution principal sont basés dans le Pas-de-Calais, près d\'Arras. L\'entreprise développe des services d\'entretien automobile innovants et des pièces détachées sous marque propre. Les stages portent sur la logistique, le commerce, le marketing, l\'e-commerce et la gestion des flux.', 10, 23, 2, 0),
(103, 'Leroy Merlin - Siège et R&D', 3500, 'https://www.leroymerlin.fr', 'recrutement@leroymerlin.fr', '0321622000', '10 Avenue Louis Breguet, Lezennes', 'Enseigne leader de l\'amélioration de l\'habitat en France, avec son siège dans les Hauts-de-France.', 'Leroy Merlin est l\'enseigne numéro 1 du bricolage et de l\'amélioration de l\'habitat en France. Son siège social et ses équipes centrales sont basés dans le Nord de la France, près d\'Arras. L\'entreprise développe une stratégie omnicanale ambitieuse et un écosystème de services autour de l\'habitat. Les stages proposés couvrent le marketing, le digital, la logistique, les RH, la data et le développement commercial.', 15, 23, 4, 0),
(104, 'Auchan Retail France - Direction', 4500, 'https://www.auchan.fr', 'recrutement@auchan.fr', '0320677000', '40 Avenue de Flandre, Villeneuve-d\'Ascq', 'Acteur majeur du commerce alimentaire et non-alimentaire, siège en Hauts-de-France.', 'Auchan est l\'un des leaders mondiaux de la grande distribution. Sa direction France, basée dans la métropole lilloise, gère un réseau d\'hypermarchés et de supermarchés. Le groupe est en pleine transformation digitale avec le développement du drive, de la livraison à domicile et de l\'intelligence artificielle en magasin. Les stages couvrent la distribution, le marketing, les achats, la logistique et les systèmes d\'information.', 20, 23, 4, 0),
(105, 'Philips Lumileds - Caen', 600, 'https://www.lumileds.com', 'recrutement.caen@lumileds.com', '0231457000', 'Zone Industrielle du Vieux-Marc, Évreux', 'Fabricant mondial de LED et systèmes d\'éclairage de haute performance.', 'Lumileds est un leader mondial dans les LED de puissance et les solutions d\'éclairage automobile et général. Son site normand, historiquement lié à Philips, fabrique des composants LED avancés pour les secteurs automobile, industriel et médical. L\'entreprise investit fortement en R&D pour améliorer les performances et l\'efficacité de ses produits. Les stages en électronique, optique, matériaux et qualité y sont très formateurs.', 6, 24, 10, 0),
(106, 'Calvados Cidre Tradition (Bolloré Agri)', 200, 'https://www.cidrerie-traditions.fr', 'contact@cidrerie-traditions.fr', '0231692000', 'Route de Vire', 'Cidrerie normande artisanale et semi-industrielle reconnue pour la qualité de ses productions.', 'Calvados Cidre Tradition est une entreprise normande spécialisée dans la production de cidres artisanaux, de calvados et de pommeau de haute qualité. Elle perpétue le savoir-faire cidricole normand tout en modernisant ses équipements de production et sa démarche commerciale. La marque est présente dans la grande distribution et l\'export. Les stages concernent la production cidricole, l\'œnologie adaptée au cidre, le marketing et la distribution.', 3, 24, 1, 0),
(107, 'Caen la Mer - Communauté Urbaine', 900, 'https://www.caenlamer.fr', 'contact@caenlamer.fr', '0231398000', 'Avenue du 6 Juin', 'Intercommunalité normande gérant les services urbains et le développement économique local.', 'Caen la Mer est la communauté urbaine regroupant la ville de Caen et ses communes périphériques. Elle assure des compétences en transports urbains, déchets, eau, développement économique et aménagement. La collectivité mène des projets structurants pour renforcer l\'attractivité du territoire normand. Les stages en urbanisme, gestion publique, communication, développement durable et administration sont ouverts à des profils variés.', 5, 24, 12, 0),
(108, 'Normandie Logistique (Groupe Bolloré)', 450, 'https://www.bollore-logistics.com', 'contact.normandie@bollore-logistics.com', '0231520000', 'Port de Caen Ouistreham', 'Opérateur logistique multimodal sur le port de Caen-Ouistreham, spécialisé dans le fret transmanche.', 'Normandie Logistique est une filiale du groupe Bolloré Logistics opérant sur le port de Caen-Ouistreham. Elle gère des opérations de transit, de fret transmanche (liaison Caen-Portsmouth) et de logistique portuaire. L\'entreprise traite des volumes importants de marchandises et accompagne ses clients dans les procédures douanières et de transport international. Les stages en logistique, transit douanier et commerce international y sont très pratiques.', 6, 24, 14, 0),
(109, 'Decathlon - Siège Mondial', 4000, 'https://www.decathlon.fr', 'recrutement.siege@decathlon.fr', '0320994344', '4 Boulevard de Mons, Villeneuve-d\'Ascq', 'Géant mondial du sport avec son siège et ses équipes de conception basés à Villeneuve-d\'Ascq.', 'Decathlon est l\'entreprise française la plus internationale dans le commerce d\'articles de sport. Son siège mondial, basé à Villeneuve-d\'Ascq près de Lille, concentre les équipes de conception produit, de marketing, de digital et de supply chain. Le groupe développe ses propres marques (Quechua, Btwin, Domyos) et investit dans la durabilité et l\'économie circulaire. Les stages au siège mondial sont particulièrement enrichissants pour les profils marketing, design, digital et supply chain.', 25, 25, 4, 0),
(110, 'Crédit Mutuel Nord Europe', 3000, 'https://www.cmne.fr', 'contact@cmne.fr', '0320987000', '4 Place Richebé', 'Banque coopérative régionale forte d\'un ancrage dans la région Nord et en Belgique.', 'Le Crédit Mutuel Nord Europe est la fédération régionale du Crédit Mutuel implantée dans les Hauts-de-France et en Belgique. Banque coopérative mutualiste, elle accompagne ses sociétaires particuliers et professionnels avec une offre complète et personnalisée. La CMNE est reconnue pour la stabilité de son modèle et sa forte culture client. Les stages en banque, finance, digital et marketing y sont accessibles sur tout le territoire.', 12, 25, 3, 0),
(111, 'EuraTechnologies', 350, 'https://www.euratechnologies.com', 'contact@euratechnologies.com', '0320192000', '165 Avenue de Bretagne', 'Pôle d\'excellence numérique lillois, premier incubateur tech de France.', 'EuraTechnologies est le premier incubateur et accélérateur de start-ups numériques de France. Implanté à Lille, il regroupe plus de 200 entreprises innovantes dans un écosystème tech dynamique. Le pôle propose des programmes d\'accompagnement, des formations et des espaces de travail partagés pour les entrepreneurs du numérique. Les stages au sein des équipes d\'EuraTechnologies ou des start-ups hébergées sont idéaux pour des profils entrepreneuriaux et tech.', 8, 25, 11, 0),
(112, 'Worldline - Centre Opérationnel Lille', 2000, 'https://www.worldline.com', 'recrutement.lille@worldline.com', '0320148000', '80 Quai Gillet', 'Leader européen des services de paiement et des transactions numériques.', 'Worldline est le leader européen des services de paiement. Son centre de Lille gère des opérations critiques de traitement de transactions bancaires et de monétique pour des milliers de clients. L\'entreprise développe des solutions innovantes en paiement mobile, e-commerce et sécurité des transactions. Les stages en développement logiciel, cybersécurité, data et ingénierie systèmes y sont extrêmement formateurs dans un secteur en forte croissance.', 15, 25, 11, 0),
(113, 'Kiloutou', 1500, 'https://www.kiloutou.fr', 'recrutement@kiloutou.fr', '0320481000', '57 Avenue Georges Pompidou, Lesquin', 'Deuxième loueur français de matériels de BTP, avec son siège en région lilloise.', 'Kiloutou est le deuxième loueur français de matériels de travaux publics, de bâtiment et d\'événementiel. Son siège social, basé à Lesquin près de Lille, gère un réseau national d\'agences de location. L\'entreprise développe ses services digitaux et renforce sa flotte de matériels électriques. Les stages concernent la logistique, la maintenance matériels, le commerce et la gestion des opérations.', 8, 25, 7, 0),
(114, 'Veolia Propreté - Direction Nord', 2200, 'https://www.veolia.com', 'contact.nord@veolia.com', '0320601500', 'Avenue de la Créativité, Villeneuve-d\'Ascq', 'Leader mondial de la gestion des déchets, de l\'eau et de l\'énergie, actif dans le Nord.', 'Veolia est un leader mondial des services à l\'environnement (eau, déchets, énergie). Sa direction Nord gère la collecte et le traitement des déchets industriels et ménagers pour de nombreuses collectivités et industriels des Hauts-de-France. L\'entreprise développe l\'économie circulaire et les valorisations de déchets (biogaz, recyclage, valorisation énergétique). Les stages portent sur la gestion des déchets, le traitement de l\'eau, le génie de l\'environnement et la logistique.', 10, 25, 15, 0),
(115, 'Norsk Hydro - Aluminerie de Nogent', 700, 'https://www.hydro.com', 'contact.france@hydro.com', '0235657000', 'Rue du Dr Gallois, Nogent-sur-Seine', 'Producteur mondial d\'aluminium et site de transformation proche de Rouen.', 'Norsk Hydro est l\'un des plus grands producteurs mondiaux d\'aluminium et de solutions en aluminium. Ses sites de transformation proches de Rouen produisent des profilés aluminium pour le bâtiment, l\'automobile et l\'industrie. L\'entreprise est pionnière dans la production d\'aluminium recyclé bas carbone. Les stages en métallurgie, production industrielle, qualité et commercial B2B sont formateurs dans un contexte industriel international.', 6, 26, 10, 0),
(116, 'Matmut - Siège Social', 1800, 'https://www.matmut.fr', 'recrutement@matmut.fr', '0235037000', '66 Rue de Sotteville', 'Mutuelle d\'assurance normande parmi les plus importantes de France, reconnue pour sa proximité.', 'La Matmut est une mutuelle d\'assurance créée en 1961 par les syndicats de la MGEN. Son siège social est à Rouen. Elle propose des assurances auto, habitation, santé et prévoyance à ses sociétaires. Reconnue pour sa politique tarifaire et ses valeurs mutualistes, la Matmut est l\'une des préférées des Français. Les stages portent sur l\'actuariat, la gestion des sinistres, le digital, le marketing et la relation client.', 10, 26, 3, 0),
(117, 'Lubrizol France', 550, 'https://www.lubrizol.com', 'contact.france@lubrizol.com', '0235536000', 'Quai Gaston Boulet', 'Leader mondial des additifs pour lubrifiants, carburants et produits de soin.', 'Lubrizol est un leader mondial des additifs de spécialité pour lubrifiants, carburants et soins personnels. Son site de Rouen est l\'un des deux principaux sites de production du groupe en France. Lubrizol développe des solutions chimiques avancées pour améliorer les performances des moteurs et réduire les émissions polluantes. Les stages en chimie, génie des procédés, QHSE et ingénierie sont très demandés dans cet environnement industriel exigeant.', 7, 26, 10, 0),
(118, 'Normandie Université (Service des Stages)', 400, 'https://www.normandie-univ.fr', 'contact.stages@normandie-univ.fr', '0235147000', '1 Rue Thomas Becket', 'Regroupement d\'universités normandes coordonnant formations et insertion professionnelle.', 'Normandie Université est un réseau d\'établissements d\'enseignement supérieur normands (universités de Rouen, Caen, Le Havre, INSA, ENSICAEN). Il coordonne des projets de recherche, de formation et de vie étudiante à l\'échelle régionale. Le service des stages accompagne les étudiants dans leur recherche de stage et leurs relations avec les entreprises partenaires. Les stages au sein des structures universitaires portent sur la gestion, la communication et l\'administration.', 5, 26, 12, 0),
(119, 'GRTgaz - Région Nord', 1200, 'https://www.grtgaz.com', 'contact.nord@grtgaz.com', '0235672000', '5 Rue de Verdun', 'Transporteur de gaz naturel haute pression, gestionnaire du réseau de transport gazier français.', 'GRTgaz est le gestionnaire du réseau de transport de gaz naturel haute pression en France. Sa région Nord, basée à Rouen, assure la maintenance et le développement du réseau gazier dans les Hauts-de-France et en Normandie. L\'entreprise intègre progressivement l\'hydrogène dans ses infrastructures. Les stages portent sur l\'ingénierie des gazoducs, la maintenance industrielle, les systèmes de contrôle et la transition énergétique.', 6, 26, 15, 0),
(120, 'CPAM de Seine-Maritime', 900, 'https://www.ameli.fr', 'contact.76@cpam.fr', '0235157000', '50 Avenue Bretagne', 'Caisse primaire d\'assurance maladie assurant la protection sociale des Seinomuriens.', 'La Caisse Primaire d\'Assurance Maladie de Seine-Maritime est l\'organisme de Sécurité Sociale en charge de la protection sociale des habitants de la Seine-Maritime. Elle gère le remboursement des soins de santé, les indemnités journalières et la prévention. La CPAM est en pleine transformation numérique avec des projets d\'intelligence artificielle et de dématérialisation. Les stages en gestion administrative, informatique, statistiques et communication y sont accessibles.', 6, 26, 12, 0),
(121, 'Vinci Construction France - Île de France', 5000, 'https://www.vinci-construction-france.com', 'recrutement.idf@vinci-construction.com', '0155676000', 'Nanterre, 61 Avenue Jules Quentin', 'Filiale française de Vinci Construction, leader BTP réalisant des projets d\'envergure nationale.', 'Vinci Construction France est la principale filiale de construction de Vinci en France. Elle réalise des ouvrages complexes : tunnels, ponts, immeubles de grande hauteur, équipements sportifs et aménagements urbains. Son agence Île-de-France est très active sur les grands projets du Grand Paris Express. Les stages en génie civil, conduite de travaux, géotechnique, BIM et gestion de chantier y sont très recherchés.', 20, 7, 7, 0),
(122, 'Dassault Systèmes - Vélizy', 6000, 'https://www.3ds.com', 'recrutement@3ds.com', '0161621000', '10 Rue Marcel Dassault, Vélizy-Villacoublay', 'Leader mondial des logiciels de conception 3D et de simulation numérique.', 'Dassault Systèmes est le leader mondial des logiciels de conception 3D et d\'expérience utilisateur virtuelle. Ses solutions (CATIA, SOLIDWORKS, SIMULIA) sont utilisées par des industriels de l\'aéronautique, automobile et de la santé dans le monde entier. Son campus de Vélizy est un centre d\'innovation majeur. Les stages en développement logiciel, simulation numérique, support technique et marketing B2B y sont extrêmement valorisants.', 25, 7, 11, 0),
(123, 'Safran - Siège Social', 7000, 'https://www.safran-group.com', 'recrutement@safran.com', '0140604000', '2 Boulevard du Général Martial Valin', 'Leader international de haute technologie en aéronautique, défense et espace.', 'Safran est un groupe international de haute technologie opérant dans les domaines de l\'aéronautique civile et militaire, de la défense et de l\'espace. Ses marques (Snecma, Labinal, Zodiac) sont des références mondiales. Le siège parisien coordonne les activités R&D, finance et stratégie des nombreuses filiales. Les stages proposés dans les équipes centrales portent sur la stratégie, la finance d\'entreprise, les systèmes d\'information et la communication institutionnelle.', 30, 7, 2, 0),
(124, 'Biomérieux - Direction Commerciale Lyon', 1500, 'https://www.biomerieux.com', 'recrutement.commercial@biomerieux.com', '0472612000', '376 Chemin de l\'Orme, Marcy-l\'Etoile', 'Direction commerciale et marketing du groupe bioMérieux, leader mondial du diagnostic in vitro.', 'bioMérieux est un leader mondial du diagnostic in vitro. Sa direction commerciale France, basée en région lyonnaise, gère les ventes, le marketing et le support technique pour les hôpitaux, laboratoires et industriels français. L\'entreprise est reconnue pour la qualité de sa relation client et son expertise scientifique. Les stages en vente de solutions médicales, marketing santé et support technique sont très enrichissants.', 8, 17, 13, 0),
(125, 'Michelin - Clermont-Ferrand (stage Grenoble)', 12000, 'https://www.michelin.com', 'recrutement@michelin.com', '0473321000', '12 Cours Sablon, Clermont-Ferrand', 'Premier fabricant de pneumatiques français et l\'un des leaders mondiaux du secteur.', 'Michelin est le numéro deux mondial du pneumatique. Son siège mondial de Clermont-Ferrand regroupe les fonctions stratégiques, R&D, marketing et manufacture du groupe. Michelin innove dans les technologies de mobilité durable (pneumatique non pneumatique, matériaux biosourcés) et développe ses services de mobilité. Les stages proposés sont très diversifiés : ingénierie, chimie, digital, logistique, finance et ressources humaines.', 20, 16, 2, 0),
(126, 'Rakuten France (PriceMinister)', 500, 'https://fr.shopping.rakuten.com', 'recrutement@rakuten.fr', '0140238000', '33 Rue Lafayette, Paris', 'Marketplace e-commerce de référence, filiale du géant japonais Rakuten.', 'Rakuten France, anciennement PriceMinister, est l\'une des plus grandes marketplaces e-commerce en France avec des millions de produits neufs, d\'occasion et de reconditionné. Filiale du groupe japonais Rakuten, elle développe des services innovants en recommandation personnalisée, paiement et fidélité. Les stages proposés portent sur l\'e-commerce, la data science, le développement web et le marketing digital.', 10, 7, 4, 0),
(127, 'BNP Paribas Cardif - Nantes', 2000, 'https://www.bnpparibascardif.com', 'recrutement.nantes@cardif.bnpparibas.com', '0240135000', 'Immeuble Maillé Brézé, 10 Rue Louis Blériot', 'Filiale d\'assurance de BNP Paribas, leader de la bancassurance et de la protection des personnes.', 'BNP Paribas Cardif est la filiale d\'assurance-vie et de protection des personnes de BNP Paribas. Son centre de gestion de Nantes traite les contrats d\'assurance-vie, de prévoyance et d\'assurance emprunteur pour des clients en France et à l\'international. L\'entreprise développe activement ses outils digitaux pour améliorer l\'expérience client. Les stages en assurance, gestion de contrats, digital et data sont très formateurs.', 10, 13, 3, 0),
(128, 'Apside - Bordeaux', 800, 'https://www.apside.com', 'recrutement.bordeaux@apside.com', '0556909000', '4 Allée de Tourny', 'ESN régionale en forte croissance, spécialisée dans les métiers du numérique.', 'Apside est une Entreprise de Services du Numérique (ESN) française fondée en 2002. Son agence de Bordeaux accompagne des entreprises régionales et nationales dans leurs projets de transformation digitale, de développement applicatif et d\'infrastructure IT. Apside se distingue par sa culture collaborative et son attention portée à la qualité de vie au travail. Les stages en développement, administration systèmes, data et gestion de projet y sont très encadrés.', 8, 19, 11, 0),
(129, 'Groupe Eiffage - Rhône-Alpes', 3500, 'https://www.eiffage.com', 'contact.rhonealpes@eiffage.com', '0472367000', '30 Rue Franklin', 'Acteur majeur de la construction et du BTP en Rhône-Alpes, filiale du groupe Eiffage.', 'Eiffage est l\'un des premiers groupes de construction européens. Son agence Rhône-Alpes réalise des projets de BTP, de génie civil, de travaux routiers et de réseaux d\'énergie dans toute la région. Le groupe est pionnier dans les méthodes de construction bas carbone et dans le BIM. Les stages en conduite de travaux, études techniques, génie civil et management de projet sont très concrets et enrichissants.', 10, 17, 7, 0),
(130, 'Sofiprotéol (Avril Group) - Bordeaux', 700, 'https://www.avril-group.com', 'contact.bordeaux@avril-group.com', '0556001000', '11 Rue Ferrère', 'Groupe coopératif agro-industriel leader des filières végétales (huile, protéines).', 'Le groupe Avril est un acteur coopératif majeur des filières végétales en France. Ses activités couvrent la production d\'huiles alimentaires (Lesieur, Puget), de protéines végétales et de biocarburants. Son agence bordelaise gère les achats de grains et les activités de négoce pour le Grand Sud-Ouest. Les stages en agronomie, commerce des matières premières, logistique agroalimentaire et marketing y sont enrichissants.', 5, 19, 1, 0),
(131, 'Inria - Centre de Rennes', 1200, 'https://www.inria.fr', 'contact.rennes@inria.fr', '0299842500', 'Campus de Beaulieu, Avenue du Général Leclerc, Rennes', 'Institut national de recherche en informatique et automatique, centre de Rennes.', 'L\'Inria est l\'institut national de recherche dédié aux sciences du numérique. Son centre de Rennes, l\'un des plus importants du réseau, réunit des équipes de recherche en intelligence artificielle, cybersécurité, réseaux et systèmes distribués. L\'Inria collabore étroitement avec les universités et les entreprises. Les stages en recherche algorithmique, IA, traitement du signal et développement logiciel y sont d\'un niveau exceptionnel.', 8, 10, 11, 0),
(132, 'Vinci Energies - Nord-Ouest', 2500, 'https://www.vinci-energies.com', 'contact.nw@vinci-energies.com', '0298640000', '10 Rue Servan, Rennes', 'Acteur majeur des installations électriques, des réseaux et des systèmes de communication.', 'Vinci Energies est une branche du groupe Vinci spécialisée dans les solutions énergétiques et numériques. Son agence Nord-Ouest réunit des marques (Omexom, Axians, Actemium) intervenant dans l\'énergie, les télécoms et l\'industrie. Les équipes installent et maintiennent des réseaux électriques, des datacenters et des systèmes industriels automatisés. Les stages en électrotechnique, automatismes, réseaux IT et génie électrique y sont très variés.', 8, 10, 15, 0),
(133, 'GRDF - Agence Strasbourg', 900, 'https://www.grdf.fr', 'contact.strasbourg@grdf.fr', '0388772000', '4 Avenue Buffon', 'Gestionnaire du réseau de distribution de gaz naturel, agence Alsace-Moselle.', 'GRDF est le principal gestionnaire du réseau de distribution de gaz naturel en France. Son agence Alsace-Moselle, basée à Strasbourg, gère l\'exploitation et la maintenance du réseau gazier de la région. L\'entreprise intègre progressivement le gaz vert (biométhane) dans son réseau. Les stages portent sur l\'exploitation des réseaux de distribution, la maintenance des ouvrages, la relation clients et la transition énergétique.', 5, 4, 15, 0),
(134, 'BTP CFA Grand Est - Strasbourg', 180, 'https://www.btp-cfa-grandest.fr', 'contact@btp-cfa-grandest.fr', '0388792000', '15 Rue des Vosges', 'Centre de formation aux métiers du BTP pour la région Grand Est.', 'BTP CFA Grand Est est le Centre de Formation des Apprentis des métiers du bâtiment et des travaux publics pour la région Grand Est. Il forme chaque année des centaines d\'apprentis aux métiers de maçon, électricien, plombier, charpentier et chef de chantier. La structure gère plusieurs sites de formation en Alsace, Lorraine et Champagne. Les stages dans le domaine de la gestion de formation, de la pédagogie et de l\'administration sont accessibles.', 3, 4, 12, 0),
(135, 'JTEKT Automotive - Reims', 800, 'https://www.jtekt.com', 'recrutement.reims@jtekt.com', '0326891000', 'Zone Industrielle, Vendeuil-Caply', 'Fabricant mondial de systèmes de direction automobiles pour les grands constructeurs.', 'JTEKT est un groupe industriel japonais leader dans les systèmes de direction automobile, les roulements et les outils de coupe. Son usine de la région rémoise produit des colonnes de direction pour Renault, PSA et d\'autres constructeurs. L\'entreprise est engagée dans la qualité totale et le lean manufacturing. Les stages en production industrielle, qualité, méthodes et maintenance sont très valorisants dans l\'industrie automobile.', 8, 3, 2, 0),
(136, 'Vinci Immobilier - Rhône-Alpes', 400, 'https://www.vinci-immobilier.com', 'contact.rhonealpes@vinci-immobilier.com', '0478426000', '69 Boulevard de Stalingrad, Villeurbanne', 'Promoteur immobilier filiale du groupe Vinci, actif dans les logements et immobilier tertiaire.', 'Vinci Immobilier est la filiale de promotion immobilière du groupe Vinci. Son agence Rhône-Alpes développe des programmes de logements neufs, de résidences gérées et d\'immobilier d\'entreprise dans la métropole lyonnaise. Le promoteur s\'engage dans des constructions à haute performance environnementale (RE2020, BBCA). Les stages portent sur le développement foncier, la gestion de programmes, la commercialisation et la relation client.', 5, 17, 9, 0),
(137, 'Pierre & Vacances Center Parcs - Direction', 2000, 'https://www.groupepvcp.com', 'recrutement@groupepvcp.com', '0185550000', '11 Rue de Cambrai', 'Leader européen du tourisme de séjour avec ses résidences de vacances et villages Center Parcs.', 'Le groupe Pierre & Vacances-Center Parcs est le leader européen des séjours et vacances en village. Il gère des centaines de résidences et villages de vacances sur tout le continent. Le groupe développe des offres alliant confort, nature et activités de loisirs. Les stages en tourisme, marketing, revenue management, accueil et management hôtelier sont accessibles dans ses structures régionales.', 15, 7, 8, 0),
(138, 'Heineken France - Schiltigheim', 1200, 'https://www.heinekenfrance.fr', 'recrutement.schiltigheim@heinekenfrance.fr', '0388194000', '4 Rue Saint-Charles, Schiltigheim', 'Principal brasseur en France, producteur des marques Heineken, Desperados, Grimbergen.', 'Heineken France est le leader du marché brassicole français. Son site historique de Schiltigheim, en banlieue de Strasbourg, est l\'une des plus grandes brasseries d\'Europe. Il produit les marques phares Heineken, Kronenbourg (sous licence), Desperados et Grimbergen. L\'entreprise investit dans des procédés de brassage éco-responsables. Les stages en production agroalimentaire, qualité, marketing et logistique sont très attractifs.', 8, 4, 1, 0),
(139, 'Altice France (SFR) - Direction Centre', 3000, 'https://www.sfr.fr', 'recrutement@sfr.fr', '0660600600', '1 Square Béla Bartók', 'Opérateur télécom SFR et ses services numériques, seconde marque française du secteur.', 'SFR, filiale du groupe Altice France, est le deuxième opérateur télécom français. Son centre de gestion toulousain couvre les activités de service client, d\'exploitation réseau et de marketing pour le Sud de la France. SFR développe la fibre, la 5G et ses services cloud pour les entreprises. Les stages en réseaux télécoms, développement commercial, relation client et marketing digital y sont disponibles pour des profils variés.', 12, 22, 11, 0),
(140, 'Demathieu & Bard Construction - Moselle', 700, 'https://www.demathieu-bard.fr', 'recrutement@demathieu-bard.fr', '0387379000', '36 Route de Woippy', 'Groupe de construction régional, expert en génie civil, ouvrages d\'art et gros œuvre.', 'Demathieu & Bard est un groupe de construction familial, indépendant et de taille intermédiaire. Son implantation historique en Lorraine, basée à Metz, lui permet de réaliser des projets de génie civil, d\'ouvrages d\'art, de tunnels et de gros œuvre dans tout le Grand Est et au-delà. L\'entreprise est reconnue pour son savoir-faire technique et sa capacité à gérer des projets complexes. Les stages en travaux, études et gestion sont très opérationnels.', 6, 5, 7, 0),
(141, 'InVivo Group - Nantes', 1500, 'https://www.invivo-group.com', 'recrutement.nantes@invivo-group.com', '0240202000', '35 Quai de Tourville', 'Union de coopératives agricoles leader de la filière grains, élevage et jardinerie.', 'InVivo est l\'un des premiers groupes coopératifs agricoles en France. Son pôle Nantes couvre les activités de négoce de grains, de distribution d\'intrants agricoles et de vente au détail via son réseau Jardiland. Le groupe développe des solutions numériques pour les agriculteurs (agritech). Les stages en agronomie, commerce agricole, marketing de distribution et digital sont accessibles pour des profils diversifiés.', 6, 13, 1, 0),
(142, 'Ingénico Group - Lyon', 1200, 'https://www.ingenico.com', 'recrutement@ingenico.com', '0473258000', '28-32 Boulevard de Grenelle', 'Leader mondial des terminaux de paiement et des solutions de commerce unifié.', 'Ingenico est le leader mondial des terminaux de paiement. Son centre de R&D de Lyon conçoit les prochaines générations de terminaux physiques et les solutions de paiement en ligne pour des millions de commerçants dans le monde. L\'entreprise opère dans plus de 100 pays. Les stages en développement embedded, sécurité des paiements, hardware, data et marketing sont très recherchés dans cet environnement fintech.', 10, 17, 11, 0),
(143, 'Grenoble Alpes Métropole', 1100, 'https://www.grenoblealpesmetropole.fr', 'contact@grenoblealpesmetropole.fr', '0476598000', '1 Place de la Communauté', 'Intercommunalité du bassin grenoblois, gestionnaire des services et aménagements du territoire.', 'Grenoble Alpes Métropole regroupe plus de 40 communes autour de Grenoble. Elle gère des compétences en transports (TAG), eau, déchets, développement économique et logement. La métropole pilote des projets ambitieux dans les smart cities, la mobilité douce et la transition énergétique. Les stages en urbanisme, développement durable, systèmes d\'information géographique, communication et politiques publiques sont très variés.', 7, 16, 12, 0);
INSERT INTO `ENTREPRISE` (`entreprise_id`, `entreprise_nom`, `entreprise_taille`, `entreprise_siteweb`, `entreprise_email`, `entreprise_telephone`, `entreprise_rue`, `entreprise_extrait`, `entreprise_presentation`, `entreprise_nb_stagiaires`, `localite_id`, `secteur_id`, `entreprise_archive`) VALUES
(144, 'Daimler Truck France', 800, 'https://www.mercedes-benz-trucks.fr', 'contact.france@daimler.com', '0238420000', 'Zone Logistique des Acacias, Saint-Jean-de-la-Ruelle', 'Importateur officiel de camions Mercedes-Benz et FUSO en France.', 'Daimler Truck France est l\'importateur officiel des camions Mercedes-Benz et FUSO pour le marché français. Son siège d\'Orléans gère les activités de vente, d\'après-vente, de formation des techniciens et de relations avec le réseau de concessionnaires. L\'entreprise développe ses solutions de véhicules électriques et connectés. Les stages en commerce B2B, service après-vente, marketing et formation technique sont accessibles.', 6, 6, 2, 0),
(145, 'GL Santé - Clinique Saint-Martin Caen', 400, 'https://www.clinique-st-martin.fr', 'recrutement@clinique-st-martin.fr', '0231065000', '18 Rue des Roquemonts', 'Clinique privée pluridisciplinaire de référence dans l\'agglomération caennaise.', 'La Clinique Saint-Martin est un établissement de santé privé de Caen proposant des soins chirurgicaux, médicaux et obstétriques de qualité. Membre du groupe GL Santé, la clinique dispose de plateaux techniques modernes et d\'une équipe médicale reconnue. Elle investit dans la formation continue de ses équipes et l\'amélioration de l\'expérience patient. Les stages en gestion hospitalière, qualité des soins, communication et accueil y sont disponibles.', 5, 24, 13, 0),
(146, 'SNCF Réseau - Rouen', 2000, 'https://www.sncf-reseau.fr', 'contact.normandie@sncf-reseau.fr', '0235667000', '9 Rue Gresset', 'Gestionnaire du réseau ferroviaire national, direction régionale Normandie.', 'SNCF Réseau est le gestionnaire des infrastructures ferroviaires en France. Sa direction Normandie, basée à Rouen, gère l\'entretien, la maintenance et le développement du réseau ferré normand. Le réseau normand est en cours de modernisation avec des investissements importants dans la sécurité et la ponctualité. Les stages en ingénierie ferroviaire, génie civil, signalisation, maintenance et gestion de projets y sont concrets et valorisants.', 8, 26, 14, 0),
(147, 'INRAE - Centre de Rennes', 1800, 'https://www.inrae.fr', 'contact.rennes@inrae.fr', '0223485000', 'Domaine de la Motte, Le Rheu', 'Institut national de recherche en agronomie et environnement, centre de Bretagne.', 'INRAE est l\'Institut National de Recherche pour l\'Agriculture, l\'Alimentation et l\'Environnement, né de la fusion INRA-Irstea. Son centre de Rennes est l\'un des plus importants, spécialisé en génétique animale, productions végétales et technologies alimentaires. INRAE collabore avec des universités et des partenaires industriels pour développer des solutions durables pour les systèmes alimentaires. Les stages en biologie, agronomie, traitement des données et biotechnologies sont d\'excellente qualité.', 10, 10, 1, 0),
(148, 'Enedis - Direction Régionale Est', 2800, 'https://www.enedis.fr', 'contact.est@enedis.fr', '0388296000', '10 Place Brant', 'Gestionnaire du réseau de distribution électrique, direction Alsace-Lorraine.', 'Enedis est le gestionnaire public du réseau de distribution électrique en France. Sa direction régionale Est, basée à Strasbourg, assure la maintenance et le développement du réseau basse et moyenne tension en Alsace et en Lorraine. Enedis déploie massivement les compteurs Linky et investit dans la digitalisation du réseau. Les stages portent sur l\'exploitation des réseaux, les raccordements, les systèmes d\'information et la transition vers le réseau intelligent (smart grid).', 8, 4, 15, 0),
(149, 'Clermont Auvergne Innovation (CAI)', 100, 'https://www.clermont-auvergne-innovation.fr', 'contact@clermont-auvergne-innovation.fr', '0473426000', '2 Allée Alan Turing', 'Agence de développement économique et d\'innovation de la métropole clermontoise.', 'Clermont Auvergne Innovation est l\'agence de développement économique de Clermont Auvergne Métropole. Elle accompagne les entreprises innovantes dans leurs projets de création, de développement et d\'internationalisation. L\'agence anime l\'écosystème d\'innovation local (startup, PME, grands groupes) et développe des partenariats avec les universités et centres de recherche. Les stages en développement économique, accompagnement entrepreneurial, communication et gestion de projets sont accessibles.', 3, 16, 12, 0),
(150, 'MAAF Assurances - Direction Régionale Atlantique', 900, 'https://www.maaf.fr', 'contact.atlantique@maaf.fr', '0549448000', '10 Place de la Cathédrale, Niort', 'Grande compagnie d\'assurances mutualiste dont le siège historique est à Niort.', 'MAAF Assurances est une compagnie d\'assurances mutualiste appartenant au groupe Covéa. Son siège historique à Niort est proche des campus de La Rochelle et Angoulême. MAAF propose des assurances auto, habitation, santé et prévoyance aux particuliers et professionnels. Reconnue pour son service client de qualité, la MAAF est en pleine transformation digitale. Les stages en assurance, actuariat, relation client, digital et marketing sont disponibles.', 8, 12, 3, 0);
