INSERT INTO `OFFRE` (`offre_id`, `offre_titre`, `offre_reference`, `offre_description`, `offre_missions`, `offre_profil`, `offre_date_debut`, `offre_duree`, `offre_remuneration`, `offre_date_publication`, `localite_id`, `entreprise_id`, `offre_archive`) VALUES
(1, 'Analyste Transport et Mobilité Urbaine', 'REF-202603-001', 'Au sein de la direction exploitation de Divia, vous analysez les flux de voyageurs et contribuez à l\'amélioration continue du réseau de transport en commun dijonnais.', 'Analyser les données de fréquentation des lignes de bus et tramway, Optimiser les horaires et les itinéraires en fonction des analyses, Réaliser des enquêtes de satisfaction auprès des voyageurs, Contribuer aux études de faisabilité de nouvelles lignes, Rédiger des notes de synthèse à destination des équipes opérationnelles.', 'Étudiant en Logistique, Transport ou Gestion des Organisations (A3 à A5). Maîtrise d\'Excel et d\'outils SIG. Sens de l\'analyse et rigueur. Bon relationnel pour les enquêtes terrain.', '2026-09-01', 4, '577.00', '2026-03-01', 1, 1, 0),
(2, 'Chef de Projet Système d\'Information Voyageurs', 'REF-202603-002', 'Vous participez à la modernisation du système d\'information voyageurs en temps réel de Divia pour améliorer l\'expérience des usagers sur l\'ensemble du réseau.', 'Contribuer au déploiement de nouvelles interfaces d\'information voyageurs (bornes, application mobile), Coordonner les équipes techniques et les prestataires IT, Tester les nouvelles fonctionnalités et rédiger les procès-verbaux de recette, Participer aux réunions de projet et aux comités de pilotage, Mettre à jour la documentation technique.', 'Étudiant en Informatique ou Gestion de Projet (A4 ou A5). Connaissance des méthodes agiles appréciée. Bon esprit d\'analyse et de synthèse. Capacité à travailler en équipe pluridisciplinaire.', '2026-07-01', 6, '577.00', '2026-03-05', 1, 1, 0),
(3, 'Chef de Projet Marketing Produit – Soins & Dispositifs Médicaux', 'REF-202603-003', 'Intégrez la direction marketing d\'Urgo Group pour contribuer au développement et au lancement de nouveaux produits de soins sur les marchés européens.', 'Participer à l\'élaboration du plan de lancement d\'un nouveau produit (packaging, positionnement, argumentaire commercial), Analyser les données de marché et les performances des produits concurrents, Préparer les présentations pour les équipes commerciales et les distributeurs, Coordonner les prestataires graphiques et les agences de communication, Assurer le suivi des tableaux de bord marketing.', 'Étudiant en Marketing, Commerce ou Communication (A4 ou A5). Créativité, rigueur et sens du détail. Maîtrise de PowerPoint et Excel. Anglais professionnel apprécié.', '2026-09-01', 4, '600.00', '2026-03-03', 1, 2, 0),
(4, 'Contrôleur de Gestion Industriel Junior', 'REF-202603-004', 'Au sein de la direction financière d\'Urgo Group, vous participez au suivi budgétaire et à la production des tableaux de bord de gestion pour les entités industrielles du groupe.', 'Participer à la clôture mensuelle des comptes (consolidation, reporting groupe), Analyser les écarts budgétaires et préparer les explications pour les managers opérationnels, Élaborer et mettre à jour les tableaux de bord financiers sous PowerBI, Contribuer au processus budgétaire annuel, Automatiser des reportings récurrents sous Excel.', 'Étudiant en Finance, Comptabilité ou Contrôle de Gestion (A4 ou A5). Maîtrise avancée d\'Excel. Rigueur et sens de la confidentialité. Anglais professionnel souhaité.', '2026-09-01', 4, '620.00', '2026-03-03', 1, 2, 0),
(5, 'Ingénieur d\'Études Génie Thermique – Froid Commercial', 'REF-202603-005', 'Au sein du bureau d\'études de Syclef Dijon, vous participez à la conception de systèmes frigorifiques pour des projets de grande distribution et d\'industrie agroalimentaire.', 'Participer à l\'étude technique de projets de réfrigération (dimensionnement, plans d\'ensemble), Réaliser des notes de calcul thermiques et hydrauliques, Sélectionner les équipements (compresseurs, évaporateurs, condenseurs) auprès des fournisseurs, Contribuer à la rédaction des dossiers techniques et de consultation, Effectuer des visites de chantier pour le suivi des travaux.', 'Étudiant en Génie Thermique, Froid ou Génie des Procédés (A3 à A5). Bases en thermodynamique et froid commercial. Maîtrise d\'AutoCAD appréciée. Rigoureux et organisé.', '2026-07-01', 3, '600.00', '2026-03-12', 1, 3, 0),
(6, 'Technicien de Maintenance CVC – Itinérant Bourgogne', 'REF-202603-006', 'Vous rejoignez une équipe de maintenance Syclef pour intervenir sur des installations de chauffage, ventilation et climatisation chez des clients industriels et tertiaires en Bourgogne.', 'Assister les techniciens lors des opérations de maintenance préventive et corrective, Participer aux diagnostics de pannes et aux interventions de dépannage, Rédiger les rapports d\'intervention dans le logiciel de GMAO, Veiller au respect des règles de sécurité lors des interventions sur site, Assurer la relation de proximité avec les clients lors des visites.', 'Étudiant en Maintenance Industrielle, Froid ou Électrotechnique (A2 à A3). Habilitations électriques ou fluides frigorigènes appréciées. Permis B requis. Sens du service client.', '2026-04-01', 4, '577.00', '2026-03-12', 1, 3, 0),
(7, 'Chef de Produit International – Fournitures Scolaires', 'REF-202603-007', 'Vous intégrez la direction marketing de Maped pour contribuer au développement et à l\'animation d\'une gamme de produits scolaires sur les marchés internationaux.', 'Analyser les besoins des consommateurs sur plusieurs marchés (Europe, Asie, Amérique Latine), Contribuer à la définition du positionnement produit et du packaging, Animer des réunions de coordination avec les équipes design et industrielles, Préparer les supports de présentation pour les filiales et les distributeurs, Assurer une veille concurrentielle internationale.', 'Étudiant en Marketing International ou Commerce (A4 ou A5). Anglais courant indispensable. Curiosité, esprit d\'analyse et sens de l\'initiative. Maîtrise de PowerPoint et Excel.', '2026-09-01', 6, '600.00', '2026-03-07', 1, 4, 0),
(8, 'Assistant Supply Chain et Gestion des Flux Export', 'REF-202603-008', 'Au sein de la direction supply chain de Maped, vous contribuez à l\'optimisation des flux logistiques entre les usines, les entrepôts et les marchés d\'exportation.', 'Suivre les indicateurs de performance logistique (taux de service, délais, coûts de transport), Participer à la planification des approvisionnements et au suivi des commandes fournisseurs, Analyser les ruptures de stock et proposer des actions correctives, Contribuer à des projets d\'amélioration des processus logistiques, Préparer des reportings pour le management.', 'Étudiant en Logistique, Supply Chain ou Gestion (A3 à A5). Maîtrise d\'Excel et idéalement d\'un ERP (SAP). Rigueur, organisation et sens de l\'analyse. Anglais fonctionnel requis.', '2026-09-01', 6, '577.00', '2026-03-07', 1, 4, 0),
(9, 'Business Analyst – Maîtrise d\'Ouvrage Bancaire', 'REF-202603-009', 'Au sein de la DSI du Crédit Agricole Centre-Est, vous participez à des projets d\'évolution des applications métiers de la banque en jouant un rôle de relais entre les équipes métiers et les équipes techniques.', 'Recueillir et analyser les besoins des utilisateurs métiers (réseau d\'agences, back-office), Rédiger des cahiers des charges fonctionnels et des spécifications détaillées, Participer aux phases de recette fonctionnelle des évolutions logicielles, Contribuer à la conduite du changement auprès des utilisateurs, Assurer le suivi des anomalies et des plans d\'action correctifs.', 'Étudiant en Informatique de Gestion, Finance ou Organisation (A4 ou A5). Capacité d\'écoute et de synthèse. Maîtrise des méthodes d\'analyse fonctionnelle. Rigueur et sens du service.', '2026-09-01', 3, '620.00', '2026-03-05', 1, 5, 0),
(10, 'Chargé de Communication Digitale et Réseaux Sociaux', 'REF-202603-010', 'Vous intégrez la direction communication du Crédit Agricole Centre-Est pour développer la présence digitale de la banque et animer ses communautés en ligne sur la région.', 'Créer et publier des contenus engageants sur les réseaux sociaux (LinkedIn, Facebook), Participer à la rédaction de newsletters et d\'emailings clients, Analyser les statistiques des actions digitales et proposer des optimisations, Contribuer à la mise à jour et à l\'amélioration du site internet, Réaliser une veille sur les tendances du marketing bancaire digital.', 'Étudiant en Communication Digitale ou Marketing (A3 à A5). Maîtrise des outils de Community Management. Bonne expression écrite. Créativité et rigueur.', '2026-06-01', 4, '577.00', '2026-03-05', 1, 5, 0),
(11, 'Technicien Audit Énergétique – Secteur Public', 'REF-202603-011', 'Vous rejoignez les équipes de Dalkia Dijon pour réaliser des audits énergétiques chez des clients collectivités et bailleurs sociaux et contribuer à l\'optimisation de leurs consommations.', 'Réaliser des audits énergétiques sur site (bâtiments publics, logements sociaux), Analyser les consommations d\'énergie et identifier les gisements d\'économies, Préparer des propositions techniques de travaux d\'amélioration (isolation, GTB, chauffage), Participer au suivi des contrats de performance énergétique, Rédiger des rapports d\'audit et des synthèses techniques.', 'Étudiant en Génie Thermique, Énergie ou BTP (A3 à A5). Bases en thermique du bâtiment appréciées. Rigoureux et autonome. Permis B souhaité pour les déplacements.', '2026-06-01', 4, '577.00', '2026-03-10', 1, 6, 0),
